import React from 'react';
import { useFlowStore } from '../store/flowStore';
import { useQuizGroupStore } from '../store/quizGroupStore';
import { soundService } from '../services/soundService';
import { QUIZ_GROUP_TYPES } from '../models/quiz.js';
import { ScreenContainer, Header, SubjectCard, BackButton } from '../components/screen';

/**
 * QuizGroupSelectScreen Component
 * Màn hình chọn nhóm bài học (Official, Community, Personal)
 */
export const QuizGroupSelectScreen = () => {
  const { goToNext } = useFlowStore();
  const { setCurrentGroup } = useQuizGroupStore();

  const groups = [
    {
      id: QUIZ_GROUP_TYPES.OFFICIAL,
      name: 'Chính thức',
      description: 'Bài test do quản trị viên tạo',
      icon: '⭐',
      color: 'from-blue-500 to-blue-600',
    },
    {
      id: QUIZ_GROUP_TYPES.COMMUNITY,
      name: 'Cộng đồng',
      description: 'Bài test do người dùng chia sẻ',
      icon: '👥',
      color: 'from-green-500 to-green-600',
    },
    {
      id: QUIZ_GROUP_TYPES.PERSONAL,
      name: 'Cá nhân',
      description: 'Bài test của riêng bạn',
      icon: '👤',
      color: 'from-purple-500 to-purple-600',
    },
  ];

  const handleSelectGroup = (group) => {
    soundService.playClick();
    setCurrentGroup(group.id);
    goToNext('subjectSelect');
  };

  return (
    <ScreenContainer>
      <Header
        title="Chọn nhóm bài học"
        subtitle="Chọn nguồn bài test bạn muốn làm"
        titleClassName="text-4xl"
      />

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {groups.map((group, index) => (
          <SubjectCard
            key={group.id}
            icon={group.icon}
            title={group.name}
            description={group.description}
            onClick={() => handleSelectGroup(group)}
            delay={index * 0.1}
            className={`bg-gradient-to-br ${group.color} text-white border-0`}
          />
        ))}
      </div>

      <BackButton onClick={() => goToNext('home')} />
    </ScreenContainer>
  );
};

