import React, { useEffect } from 'react';
import confetti from 'canvas-confetti';

/**
 * Confetti Component
 * Hiệu ứng confetti khi hoàn thành quiz
 */
export const Confetti = ({ trigger = false, duration = 3000 }) => {
  useEffect(() => {
    if (trigger) {
      const end = Date.now() + duration;

      const interval = setInterval(() => {
        if (Date.now() > end) {
          clearInterval(interval);
          return;
        }

        confetti({
          particleCount: 2,
          angle: 60,
          spread: 55,
          origin: { x: 0 },
          colors: ['#ef4444', '#0ea5e9', '#10b981', '#f59e0b'],
        });
        confetti({
          particleCount: 2,
          angle: 120,
          spread: 55,
          origin: { x: 1 },
          colors: ['#ef4444', '#0ea5e9', '#10b981', '#f59e0b'],
        });
      }, 25);
    }
  }, [trigger, duration]);

  return null;
};

