/**
 * Scoring Service
 * Tính điểm theo 2 chế độ: Cơ bản và Theo thời gian
 */

/**
 * Chế độ tính điểm: Cơ bản
 * Mỗi câu đúng = 1 điểm, tổng quy về 100
 * @param {number} correctAnswers - Số câu trả lời đúng
 * @param {number} totalQuestions - Tổng số câu hỏi
 * @returns {number} Điểm từ 0-100
 */
export const calculateBasicScore = (correctAnswers, totalQuestions) => {
  if (totalQuestions === 0) return 0;
  return Math.round((correctAnswers / totalQuestions) * 100);
};

/**
 * Chế độ tính điểm: Theo thời gian
 * Điểm câu = 100 / số câu * (1 + thời gian còn lại / thời gian tối đa)
 * @param {Array<Object>} answers - Mảng các câu trả lời: [{ correct: boolean, timeRemaining: number, maxTime: number }]
 * @param {number} totalQuestions - Tổng số câu hỏi
 * @returns {number} Điểm từ 0-100
 */
export const calculateTimeBasedScore = (answers, totalQuestions) => {
  if (totalQuestions === 0 || !answers || answers.length === 0) return 0;

  let totalScore = 0;
  const basePointsPerQuestion = 100 / totalQuestions;

  answers.forEach((answer) => {
    if (answer.correct) {
      const timeBonus = answer.timeRemaining && answer.maxTime 
        ? answer.timeRemaining / answer.maxTime 
        : 0;
      const questionScore = basePointsPerQuestion * (1 + timeBonus);
      totalScore += questionScore;
    }
  });

  // Đảm bảo điểm không vượt quá 100
  return Math.min(Math.round(totalScore), 100);
};

/**
 * Tính điểm tổng hợp
 * @param {string} mode - Chế độ tính điểm: 'basic' hoặc 'time'
 * @param {Object} data - Dữ liệu: { correctAnswers, totalQuestions, answers }
 * @returns {number} Điểm từ 0-100
 */
export const calculateScore = (mode, data) => {
  const { correctAnswers, totalQuestions, answers } = data;

  if (mode === 'time' && answers && answers.length > 0) {
    return calculateTimeBasedScore(answers, totalQuestions);
  }

  return calculateBasicScore(correctAnswers || 0, totalQuestions || 0);
};

/**
 * Xác định mức độ đánh giá dựa trên điểm số
 * @param {number} score - Điểm từ 0-100
 * @returns {Object} { level: string, message: string, emoji: string }
 */
export const getScoreLevel = (score) => {
  if (score >= 90) {
    return {
      level: 'excellent',
      message: 'Xuất sắc!',
      emoji: '🌟',
      color: 'text-green-600',
    };
  } else if (score >= 70) {
    return {
      level: 'good',
      message: 'Tốt lắm!',
      emoji: '👍',
      color: 'text-blue-600',
    };
  } else if (score >= 50) {
    return {
      level: 'average',
      message: 'Cố gắng thêm nhé!',
      emoji: '💪',
      color: 'text-yellow-600',
    };
  } else {
    return {
      level: 'needs-improvement',
      message: 'Học lại nhé!',
      emoji: '📚',
      color: 'text-red-600',
    };
  }
};

