import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Button } from '../components/Button';
import { Card } from '../components/Card';
import { Confetti } from '../components/Confetti';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { usePlayerStore } from '../store/playerStore';
import { getScoreLevel } from '../services/scoringService';
import { saveQuizResult } from '../services/storageService';
import { checkAndAwardBadges } from '../services/badgeService';
import { getPlayerResults } from '../services/storageService';
import { soundService } from '../services/soundService';
import { ScreenContainer, StatsCard } from '../components/screen';

/**
 * ResultScreen Component
 * Màn hình hiển thị kết quả bài làm
 */
export const ResultScreen = () => {
  const { goToNext } = useFlowStore();
  const { quizResult, currentLesson } = useQuizStore();
  const { currentPlayer } = usePlayerStore();
  const [showConfetti, setShowConfetti] = useState(false);
  const [newBadges, setNewBadges] = useState([]);

  useEffect(() => {
    if (quizResult) {
      saveResult();
      checkBadges();
      
      if (quizResult.score >= 90) {
        setShowConfetti(true);
        setTimeout(() => setShowConfetti(false), 3000);
      }
    }
  }, []);

  const saveResult = async () => {
    try {
      await saveQuizResult({
        playerId: currentPlayer?.id,
        quizId: currentLesson?.id,
        score: quizResult.score,
        totalQuestions: quizResult.totalQuestions,
        correctAnswers: quizResult.correctAnswers,
        timestamp: Date.now(),
      });
    } catch (error) {
      console.error('Error saving result:', error);
    }
  };

  const checkBadges = async () => {
    try {
      const results = await getPlayerResults(currentPlayer?.id);
      const earnedBadges = []; // TODO: Load from storage
      const badges = checkAndAwardBadges(results, earnedBadges);
      if (badges.length > 0) {
        setNewBadges(badges);
        badges.forEach(() => soundService.playBadge());
      }
    } catch (error) {
      console.error('Error checking badges:', error);
    }
  };

  if (!quizResult) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <p className="text-xl text-gray-600">Đang tải kết quả...</p>
      </ScreenContainer>
    );
  }

  const scoreLevel = getScoreLevel(quizResult.score);

  return (
    <ScreenContainer maxWidth="2xl">
      <Confetti trigger={showConfetti} />
      
      <motion.div
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.5 }}
      >
        <Card className="text-center">
          <motion.div
            className="text-8xl mb-4"
            animate={{ 
              scale: [1, 1.2, 1],
              rotate: [0, 10, -10, 0]
            }}
            transition={{ duration: 0.5, repeat: 2 }}
          >
            {scoreLevel.emoji}
          </motion.div>
          
          <h1 className="text-4xl font-bold text-gray-800 mb-2">
            {scoreLevel.message}
          </h1>
          
          <div className={`text-6xl font-bold mb-4 ${scoreLevel.color}`}>
            {quizResult.score} / 100
          </div>

          <div className="grid grid-cols-2 gap-4 mb-6">
            <StatsCard
              value={quizResult.correctAnswers}
              label="Câu đúng"
              valueColor="text-green-600 text-2xl"
            />
            <StatsCard
              value={quizResult.totalQuestions}
              label="Tổng số câu"
              valueColor="text-gray-800 text-2xl"
            />
          </div>

            {newBadges.length > 0 && (
              <motion.div
                className="mb-6"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
              >
                <h3 className="text-xl font-semibold text-gray-800 mb-3">
                  🎉 Huy hiệu mới!
                </h3>
                <div className="flex justify-center gap-4">
                  {newBadges.map((badge) => (
                    <motion.div
                      key={badge.id}
                      className="text-4xl"
                      animate={{ 
                        scale: [1, 1.3, 1],
                        rotate: [0, 360]
                      }}
                      transition={{ duration: 0.6 }}
                    >
                      {badge.emoji}
                    </motion.div>
                  ))}
                </div>
              </motion.div>
            )}

            <div className="flex gap-4">
              <Button
                onClick={() => goToNext('reward')}
                variant="primary"
                size="lg"
                className="flex-1"
              >
                Xem phần thưởng! 🎁
              </Button>
              <Button
                onClick={() => goToNext('home')}
                variant="outline"
                size="lg"
                className="flex-1"
              >
                Về trang chủ
              </Button>
            </div>
          </Card>
        </motion.div>
    </ScreenContainer>
  );
};

