import React, { useEffect } from 'react';
import { AnimatePresence } from 'framer-motion';
import { useFlowStore } from './store/flowStore';
import { initDB } from './services/storageService';
import { soundService } from './services/soundService';
import { syncOfficialQuizzes } from './services/syncService.js';
import './utils/testCloudConnection.js'; // Load test utilities

// Import all screens
import { IntroScreen } from './screens/IntroScreen';
import { SelectPlayerScreen } from './screens/SelectPlayerScreen';
import { HomeScreen } from './screens/HomeScreen';
import { LevelSelectScreen } from './screens/LevelSelectScreen';
import { SubjectSelectScreen } from './screens/SubjectSelectScreen';
import { QuizTypeSelectScreen } from './screens/QuizTypeSelectScreen';
import { QuizFilterScreen } from './screens/QuizFilterScreen';
import { QuizListScreen } from './screens/QuizListScreen';
import { QuizGroupSelectScreen } from './screens/QuizGroupSelectScreen';
import { ImportQuizScreen } from './screens/ImportQuizScreen';
import { LessonSelectScreen } from './screens/LessonSelectScreen';
import { LessonDetailScreen } from './screens/LessonDetailScreen';
import { QuestionCountScreen } from './screens/QuestionCountScreen';
import { QuizSettingsScreen } from './screens/QuizSettingsScreen';
import { QuizScreen } from './screens/QuizScreen';
import { ResultScreen } from './screens/ResultScreen';
import { RewardScreen } from './screens/RewardScreen';
import { SettingsScreen } from './screens/SettingsScreen';

/**
 * Screen Component Map
 * Map component name to actual component
 */
const screenComponents = {
  IntroScreen,
  SelectPlayerScreen,
  HomeScreen,
  LevelSelectScreen,
  SubjectSelectScreen,
  QuizTypeSelectScreen,
  QuizFilterScreen,
  QuizListScreen,
  QuizGroupSelectScreen,
  ImportQuizScreen,
  LessonSelectScreen,
  LessonDetailScreen,
  QuestionCountScreen,
  QuizSettingsScreen,
  QuizScreen,
  ResultScreen,
  RewardScreen,
  SettingsScreen,
};

/**
 * App Component
 * Main application component với FlowManager integration
 */
function App() {
  const { currentScreen } = useFlowStore();

  useEffect(() => {
    let isMounted = true;

    // Khởi tạo IndexedDB
    initDB().catch(console.error);
    
    // Khởi tạo sound service
    soundService.init();

    const runSync = () => {
      syncOfficialQuizzes().catch((error) => {
        console.error('Auto sync official quizzes failed:', error);
      });
    };

    // Sync ngay khi load trang
    runSync();

    // Sync mỗi lần người dùng reload/xem lại tab (visibilitychange)
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        runSync();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      isMounted = false;
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, []);

  // Lấy component tương ứng với currentScreen
  const CurrentScreenComponent = currentScreen
    ? screenComponents[currentScreen.component]
    : null;

  // Debug log
  useEffect(() => {
    console.log('App currentScreen:', currentScreen);
    if (currentScreen) {
      console.log('Current screen component:', currentScreen.component);
      console.log('Component exists:', !!screenComponents[currentScreen.component]);
    }
  }, [currentScreen]);

  return (
    <div className="App min-h-screen">
      <AnimatePresence mode="wait">
        {CurrentScreenComponent ? (
          <CurrentScreenComponent key={currentScreen.id} />
        ) : (
          <div className="min-h-screen bg-gradient-to-br from-primary-100 to-secondary-100 flex items-center justify-center">
            <div className="text-center">
              <p className="text-xl text-gray-600">Đang tải...</p>
              {currentScreen && (
                <p className="text-sm text-gray-500 mt-2">
                  Screen: {currentScreen.id} ({currentScreen.component})
                </p>
              )}
            </div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default App;

