import { create } from 'zustand';
import { initFlow, goToNext, goToScreen, getCurrentScreen, getFlowConfig } from '../services/flowManager';

// Default flow config - phải match với flow.json
const defaultFlowConfig = [
  { "id": "intro", "component": "IntroScreen", "next": "selectPlayer" },
  { "id": "selectPlayer", "component": "SelectPlayerScreen", "next": "home" },
  { "id": "home", "component": "HomeScreen", "next": ["levelSelect", "quizFilter", "stats", "settings"] },
  { "id": "levelSelect", "component": "LevelSelectScreen", "next": "subjectSelect" },
  { "id": "subjectSelect", "component": "SubjectSelectScreen", "next": "quizTypeSelect" },
  { "id": "quizTypeSelect", "component": "QuizTypeSelectScreen", "next": "quizList" },
  { "id": "quizFilter", "component": "QuizFilterScreen", "next": "quizList" },
  { "id": "quizGroupSelect", "component": "QuizGroupSelectScreen", "next": "subjectSelect" },
  { "id": "quizList", "component": "QuizListScreen", "next": "questionCount" },
  { "id": "questionCount", "component": "QuestionCountScreen", "next": "quizSettings" },
  { "id": "quizSettings", "component": "QuizSettingsScreen", "next": "quiz" },
  { "id": "quiz", "component": "QuizScreen", "next": "result" },
  { "id": "result", "component": "ResultScreen", "next": "reward" },
  { "id": "reward", "component": "RewardScreen", "next": "home" },
  { "id": "settings", "component": "SettingsScreen", "next": "home" },
  { "id": "importQuiz", "component": "ImportQuizScreen", "next": "home" },
  { "id": "lessonSelect", "component": "LessonSelectScreen", "next": "questionCount" }
];

// Initialize flow config immediately
initFlow(defaultFlowConfig);

/**
 * Flow Store
 * Quản lý state của flow navigation
 */
export const useFlowStore = create((set, get) => {
  return {
    currentScreen: getCurrentScreen(),
    flowConfig: getFlowConfig(),

    goToNext: (nextId = null) => {
      const nextScreen = goToNext(nextId);
      set({ currentScreen: nextScreen });
      return nextScreen;
    },

    goToScreen: (screenId) => {
      const screen = goToScreen(screenId);
      set({ currentScreen: screen });
      return screen;
    },

    getCurrentScreen: () => {
      return getCurrentScreen();
    },
  };
});
