/**
 * Storage Service
 * Lưu kết quả local bằng IndexedDB và đồng bộ Firebase (optional)
 */

import { openDB } from 'idb';

const DB_NAME = 'EduQuizDB';
const DB_VERSION = 3; // Increment version để upgrade schema (thêm levelId, subjectId)
const STORE_QUIZZES = 'quizzes';
const STORE_RESULTS = 'results';
const STORE_PLAYERS = 'players';
const STORE_QUIZ_METADATA = 'quizMetadata'; // Store riêng cho metadata

let db = null;

/**
 * Khởi tạo IndexedDB
 * @returns {Promise<IDBDatabase>} Database instance
 */
export const initDB = async () => {
  if (db) return db;

  try {
    db = await openDB(DB_NAME, DB_VERSION, {
      upgrade(db, oldVersion) {
        // Tạo store cho quizzes (full quiz data với questions)
        if (!db.objectStoreNames.contains(STORE_QUIZZES)) {
          const quizzesStore = db.createObjectStore(STORE_QUIZZES, { keyPath: 'id' });
          // Old indexes (backward compatibility)
          quizzesStore.createIndex('group', 'group');
          quizzesStore.createIndex('subject', 'subject');
          // New indexes
          quizzesStore.createIndex('levelId', 'levelId');
          quizzesStore.createIndex('subjectId', 'subjectId');
          quizzesStore.createIndex('quizType', 'quizType');
          quizzesStore.createIndex('levelSubject', ['levelId', 'subjectId']);
          quizzesStore.createIndex('levelType', ['levelId', 'quizType']);
          quizzesStore.createIndex('subjectType', ['subjectId', 'quizType']);
          quizzesStore.createIndex('creatorId', 'creatorId');
          quizzesStore.createIndex('cachedAt', 'cachedAt');
        }

        // Tạo store cho quiz metadata (chỉ metadata, không có questions)
        if (!db.objectStoreNames.contains(STORE_QUIZ_METADATA)) {
          const metadataStore = db.createObjectStore(STORE_QUIZ_METADATA, { keyPath: 'id' });
          // Old indexes (backward compatibility)
          metadataStore.createIndex('group', 'group');
          metadataStore.createIndex('subject', 'subject');
          // New indexes
          metadataStore.createIndex('levelId', 'levelId');
          metadataStore.createIndex('subjectId', 'subjectId');
          metadataStore.createIndex('quizType', 'quizType');
          metadataStore.createIndex('levelSubject', ['levelId', 'subjectId']);
          metadataStore.createIndex('levelType', ['levelId', 'quizType']);
          metadataStore.createIndex('subjectType', ['subjectId', 'quizType']);
          metadataStore.createIndex('creatorId', 'creatorId');
          metadataStore.createIndex('createdAt', 'createdAt');
          metadataStore.createIndex('usageCount', 'usageCount');
        }

        // Tạo store cho results
        if (!db.objectStoreNames.contains(STORE_RESULTS)) {
          const resultsStore = db.createObjectStore(STORE_RESULTS, { keyPath: 'id', autoIncrement: true });
          resultsStore.createIndex('playerId', 'playerId');
          resultsStore.createIndex('quizId', 'quizId');
          resultsStore.createIndex('timestamp', 'timestamp');
        }

        // Tạo store cho players
        if (!db.objectStoreNames.contains(STORE_PLAYERS)) {
          db.createObjectStore(STORE_PLAYERS, { keyPath: 'id' });
        }

        // Migration: Nếu upgrade từ version 1, migrate old quiz data
        if (oldVersion < 2) {
          // Migrate old quiz format to new format
          // This will be handled by cacheQuiz function
        }
      },
    });

    return db;
  } catch (error) {
    console.error('Error initializing IndexedDB:', error);
    throw error;
  }
};

/**
 * Lưu kết quả quiz
 * @param {Object} result - Kết quả: { playerId, quizId, score, answers, timestamp }
 * @returns {Promise<string>} ID của kết quả đã lưu
 */
export const saveQuizResult = async (result) => {
  try {
    const database = await initDB();
    const timestamp = result.timestamp || Date.now();
    
    const resultData = {
      ...result,
      timestamp,
    };

    const id = await database.add(STORE_RESULTS, resultData);
    return id;
  } catch (error) {
    console.error('Error saving quiz result:', error);
    throw error;
  }
};

/**
 * Lấy lịch sử kết quả của player
 * @param {string} playerId - ID của player
 * @returns {Promise<Array>} Mảng các kết quả
 */
export const getPlayerResults = async (playerId) => {
  try {
    const database = await initDB();
    const index = database.transaction(STORE_RESULTS).store.index('playerId');
    const results = await index.getAll(playerId);
    return results.sort((a, b) => b.timestamp - a.timestamp);
  } catch (error) {
    console.error('Error getting player results:', error);
    return [];
  }
};

/**
 * Lấy tất cả kết quả làm bài (dùng cho thống kê)
 * @returns {Promise<Array>}
 */
export const getAllQuizResults = async () => {
  try {
    const database = await initDB();
    const store = database.transaction(STORE_RESULTS).store;
    const results = await store.getAll();
    return Array.isArray(results) ? results : [];
  } catch (error) {
    console.error('Error getting all quiz results:', error);
    return [];
  }
};

/**
 * Lưu player
 * @param {Object} player - Thông tin player: { id, name, avatar, createdAt }
 * @returns {Promise<void>}
 */
export const savePlayer = async (player) => {
  try {
    const database = await initDB();
    await database.put(STORE_PLAYERS, player);
  } catch (error) {
    console.error('Error saving player:', error);
    throw error;
  }
};

/**
 * Lấy tất cả players
 * @returns {Promise<Array>} Mảng các players
 */
export const getAllPlayers = async () => {
  try {
    const database = await initDB();
    return await database.getAll(STORE_PLAYERS);
  } catch (error) {
    console.error('Error getting players:', error);
    return [];
  }
};

/**
 * Lưu quiz vào cache (full data với metadata và questions)
 * @param {Object} quizData - Quiz data object (có metadata và questions)
 * @returns {Promise<void>}
 */
export const cacheQuiz = async (quizData) => {
  try {
    const database = await initDB();
    
    // Save full quiz data (với questions)
    await database.put(STORE_QUIZZES, {
      ...quizData,
      cachedAt: quizData.cachedAt || Date.now(),
    });

    // Save metadata separately (không có questions để query nhanh)
    const { questions, cachedAt, ...metadata } = quizData;
    await database.put(STORE_QUIZ_METADATA, {
      ...metadata,
      cachedAt: cachedAt || Date.now(),
    });
  } catch (error) {
    console.error('Error caching quiz:', error);
    throw error;
  }
};

/**
 * Lấy quiz từ cache (full data)
 * @param {string} quizId - ID của quiz
 * @returns {Promise<Object|null>} Quiz data hoặc null
 */
export const getCachedQuiz = async (quizId) => {
  try {
    const database = await initDB();
    const quiz = await database.get(STORE_QUIZZES, quizId);
    return quiz || null;
  } catch (error) {
    console.error('Error getting cached quiz:', error);
    return null;
  }
};

/**
 * Lấy tất cả quiz metadata (không có questions) theo filter
 * @param {Object} filter - Filter options: { levelId, subjectId, quizType, creatorId, group, subject (backward compat) }
 * @returns {Promise<Array>} Array of quiz metadata
 */
export const getAllCachedQuizzes = async (filter = {}) => {
  try {
    const database = await initDB();
    const store = database.transaction(STORE_QUIZ_METADATA).store;
    
    let quizzes = [];
    
    // New filter system (levelId, subjectId, quizType)
    if (filter.levelId && filter.subjectId && filter.quizType) {
      // Query by level, subject, and type
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => 
        q.levelId === filter.levelId &&
        q.subjectId === filter.subjectId &&
        (q.quizType || q.group) === filter.quizType
      );
    } else if (filter.levelId && filter.subjectId) {
      // Query by level and subject
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => 
        q.levelId === filter.levelId &&
        q.subjectId === filter.subjectId
      );
    } else if (filter.levelId && filter.quizType) {
      // Query by level and type
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => 
        q.levelId === filter.levelId &&
        (q.quizType || q.group) === filter.quizType
      );
    } else if (filter.subjectId && filter.quizType) {
      // Query by subject and type
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => 
        q.subjectId === filter.subjectId &&
        (q.quizType || q.group) === filter.quizType
      );
    } else if (filter.levelId) {
      // Query by level only
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => q.levelId === filter.levelId);
    } else if (filter.subjectId) {
      // Query by subject only
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => q.subjectId === filter.subjectId);
    } else if (filter.quizType) {
      // Query by type only
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => (q.quizType || q.group) === filter.quizType);
    }
    // Backward compatibility: old filter system
    else if (filter.group && filter.subject) {
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => 
        (q.group || q.quizType) === filter.group &&
        (q.subject || q.subjectId) === filter.subject
      );
    } else if (filter.group) {
      const allQuizzes = await store.getAll();
      quizzes = allQuizzes.filter(q => (q.group || q.quizType) === filter.group);
    } else if (filter.creatorId) {
      // Query by creator
      const creatorIndex = store.index('creatorId');
      quizzes = await creatorIndex.getAll(filter.creatorId);
    } else {
      // Get all
      quizzes = await store.getAll();
    }
    
    // Sort
    const sortBy = filter.sortBy || 'createdAt';
    if (sortBy === 'usage') {
      quizzes.sort((a, b) => (b.usageCount || 0) - (a.usageCount || 0));
    } else if (sortBy === 'rating') {
      quizzes.sort((a, b) => (b.rating || 0) - (a.rating || 0));
    } else {
      quizzes.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
    }
    
    return quizzes;
  } catch (error) {
    console.error('Error getting all cached quizzes:', error);
    return [];
  }
};

/**
 * Lấy quiz metadata (không có questions)
 * @param {string} quizId - ID của quiz
 * @returns {Promise<Object|null>} Quiz metadata hoặc null
 */
export const getQuizMetadata = async (quizId) => {
  try {
    const database = await initDB();
    const metadata = await database.get(STORE_QUIZ_METADATA, quizId);
    return metadata || null;
  } catch (error) {
    console.error('Error getting quiz metadata:', error);
    return null;
  }
};

/**
 * Xóa cache cũ (quá 7 ngày)
 * @returns {Promise<number>} Số lượng cache đã xóa
 */
export const clearOldCache = async () => {
  try {
    const database = await initDB();
    const store = database.transaction(STORE_QUIZZES, 'readwrite').store;
    const allQuizzes = await store.getAll();
    const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
    
    let deletedCount = 0;
    for (const quiz of allQuizzes) {
      if (quiz.cachedAt < sevenDaysAgo) {
        await store.delete(quiz.id);
        deletedCount++;
      }
    }
    
    return deletedCount;
  } catch (error) {
    console.error('Error clearing old cache:', error);
    return 0;
  }
};

