/**
 * Quiz Management Service
 * Service quản lý bài test theo 3 nhóm: official, community, personal
 */

import { QUIZ_GROUP_TYPES, QUIZ_SOURCE_TYPES, createQuizMetadata, createQuizData } from '../models/quiz.js';
import { fetchFromGoogleSheetCSV, fetchFromGoogleSheetById } from './googleSheetService.js';
import { cacheQuiz, getCachedQuiz, getAllCachedQuizzes } from './storageService.js';
import { cloudQuizzes } from './cloudService.js';

/**
 * Load danh sách bài test cho một môn học trong nhóm
 * @param {string} group - Group type (official, community, personal)
 * @param {string} subjectId - Subject ID (math, vietnamese, english)
 * @param {string} userId - User ID (cho personal và community)
 * @returns {Promise<Array>} Array of quiz metadata
 */
export const loadQuizList = async (group, subjectId, userId = null) => {
  try {
    let quizzes = [];

    if (group === QUIZ_GROUP_TYPES.OFFICIAL) {
      // Try cloud first
      try {
        const cloudQuizzesResponse = await cloudQuizzes.getQuizzes({
          subjectId,
          quizType: QUIZ_GROUP_TYPES.OFFICIAL,
          sortBy: 'created_at',
        });
        quizzes = Array.isArray(cloudQuizzesResponse)
          ? cloudQuizzesResponse
          : cloudQuizzesResponse?.results || [];

        if (quizzes.length > 0) {
          return quizzes.map((quiz) => ({
            ...quiz,
            subject: quiz.subject_id,
            group: quiz.quiz_type,
          }));
        }
      } catch (error) {
        console.warn('loadQuizList: cloud fetch failed, fallback to cache', error);
      }

      // Fallback: cache
      quizzes = await loadOfficialQuizzes(subjectId);
    } else if (group === QUIZ_GROUP_TYPES.COMMUNITY) {
      quizzes = await loadCommunityQuizzes(subjectId);
    } else if (group === QUIZ_GROUP_TYPES.PERSONAL) {
      quizzes = await loadPersonalQuizzes(subjectId, userId);
    }

    return quizzes;
  } catch (error) {
    console.error(`Error loading quiz list for ${group}/${subjectId}:`, error);
    return [];
  }
};

/**
 * Load official quizzes (từ database đã cache)
 */
const loadOfficialQuizzes = async (subjectId) => {
  try {
    // Load từ IndexedDB (đã cache từ Google Sheets)
    const cachedQuizzes = await getAllCachedQuizzes();
    
    return cachedQuizzes
      .filter(quiz => 
        quiz.group === QUIZ_GROUP_TYPES.OFFICIAL && 
        quiz.subject === subjectId
      )
      .map(quiz => ({
        ...quiz,
        source: QUIZ_SOURCE_TYPES.DATABASE,
      }));
  } catch (error) {
    console.error('Error loading official quizzes:', error);
    return [];
  }
};

/**
 * Load community quizzes (từ database)
 */
const loadCommunityQuizzes = async (subjectId) => {
  try {
    // TODO: Load từ cloud database (Cloudflare D1 hoặc tương tự)
    // Hiện tại load từ IndexedDB local
    const cachedQuizzes = await getAllCachedQuizzes();
    
    return cachedQuizzes
      .filter(quiz => 
        quiz.group === QUIZ_GROUP_TYPES.COMMUNITY && 
        quiz.subject === subjectId &&
        quiz.isPublic === true
      )
      .sort((a, b) => b.usageCount - a.usageCount) // Sort by popularity
      .map(quiz => ({
        ...quiz,
        source: QUIZ_SOURCE_TYPES.DATABASE,
      }));
  } catch (error) {
    console.error('Error loading community quizzes:', error);
    return [];
  }
};

/**
 * Load personal quizzes (của người dùng)
 */
const loadPersonalQuizzes = async (subjectId, userId) => {
  try {
    if (!userId) return [];
    
    // Load từ IndexedDB local
    const cachedQuizzes = await getAllCachedQuizzes();
    
    return cachedQuizzes
      .filter(quiz => 
        quiz.group === QUIZ_GROUP_TYPES.PERSONAL && 
        quiz.subject === subjectId &&
        quiz.creatorId === userId
      )
      .sort((a, b) => b.createdAt - a.createdAt) // Sort by newest
      .map(quiz => ({
        ...quiz,
        source: QUIZ_SOURCE_TYPES.DATABASE,
      }));
  } catch (error) {
    console.error('Error loading personal quizzes:', error);
    return [];
  }
};

/**
 * Load bài test cụ thể (bao gồm câu hỏi)
 * @param {string} quizId - Quiz ID
 * @param {string} group - Group type
 * @returns {Promise<Object>} Quiz data với questions
 */
export const loadQuizData = async (quizId, group) => {
  try {
    // Thử load từ cache trước
    const cached = await getCachedQuiz(quizId);
    if (cached && cached.questions && cached.questions.length > 0) {
      // Update usage count
      await updateQuizUsageCount(quizId);
      return cached;
    }

    // Nếu chưa có cache, load từ source
    if (group === QUIZ_GROUP_TYPES.OFFICIAL) {
      return await loadOfficialQuizData(quizId);
    } else if (group === QUIZ_GROUP_TYPES.COMMUNITY) {
      return await loadCommunityQuizData(quizId);
    } else if (group === QUIZ_GROUP_TYPES.PERSONAL) {
      return await loadPersonalQuizData(quizId);
    }

    return null;
  } catch (error) {
    console.error(`Error loading quiz data for ${quizId}:`, error);
    throw error;
  }
};

/**
 * Load official quiz data
 * - Nếu đã cache: load từ database
 * - Nếu chưa: load từ Google Sheet → cache vào database
 */
const loadOfficialQuizData = async (quizId) => {
  // Thử load từ cache
  const cached = await getCachedQuiz(quizId);
  if (cached && cached.questions && cached.questions.length > 0) {
    return cached;
  }

  // Load từ Google Sheet (nếu có sourceUrl)
  // TODO: Load metadata từ database để lấy sourceUrl
  // Hiện tại: fallback về Google Sheets config
  const { sheetsConfig } = await import('../config/sheets.config.js');
  const config = sheetsConfig[quizId] || sheetsConfig.math; // Fallback
  
  if (config.url || config.sheetId) {
    const questions = config.url
      ? await fetchFromGoogleSheetCSV(config.url)
      : await fetchFromGoogleSheetById(config.sheetId, config.gid);

    const quizData = createQuizData({
      metadata: createQuizMetadata({
        id: quizId,
        title: `Bài test ${quizId}`,
        description: '',
        subject: quizId,
        group: QUIZ_GROUP_TYPES.OFFICIAL,
        source: QUIZ_SOURCE_TYPES.GOOGLE_SHEET,
        sourceUrl: config.url || buildSheetUrl(config.sheetId, config.gid),
        questionCount: questions.length,
        isVerified: true,
      }),
      questions,
      cachedAt: Date.now(),
    });

    // Cache vào database
    await cacheQuiz(quizData);

    return quizData;
  }

  return null;
};

/**
 * Load community quiz data
 */
const loadCommunityQuizData = async (quizId) => {
  // Load từ database (đã được người dùng upload)
  const cached = await getCachedQuiz(quizId);
  if (cached) {
    await updateQuizUsageCount(quizId);
    return cached;
  }

  // Nếu chưa có, có thể load từ Google Sheet của người tạo
  // TODO: Implement
  return null;
};

/**
 * Load personal quiz data
 */
const loadPersonalQuizData = async (quizId) => {
  // Load từ IndexedDB local
  const cached = await getCachedQuiz(quizId);
  if (cached) {
    return cached;
  }

  // Nếu chưa có, load từ Google Sheet của người dùng
  // TODO: Implement
  return null;
};

/**
 * Update usage count cho quiz
 */
const updateQuizUsageCount = async (quizId) => {
  try {
    const quiz = await getCachedQuiz(quizId);
    if (quiz) {
      quiz.usageCount = (quiz.usageCount || 0) + 1;
      quiz.updatedAt = Date.now();
      await cacheQuiz(quiz);
    }
  } catch (error) {
    console.error('Error updating usage count:', error);
  }
};

/**
 * Create new quiz (cho community hoặc personal)
 * @param {Object} quizData - Quiz data
 * @param {string} userId - User ID
 * @returns {Promise<Object>} Created quiz
 */
export const createQuiz = async (quizData, userId) => {
  try {
    const metadata = createQuizMetadata({
      ...quizData,
      id: `quiz_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      creatorId: userId,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      usageCount: 0,
    });

    const fullQuizData = createQuizData({
      metadata,
      questions: quizData.questions || [],
      cachedAt: Date.now(),
    });

    // Save to database
    await cacheQuiz(fullQuizData);

    return fullQuizData;
  } catch (error) {
    console.error('Error creating quiz:', error);
    throw error;
  }
};

/**
 * Import quiz từ Google Sheet (cho personal hoặc community)
 * @param {string} sheetUrl - Google Sheet URL
 * @param {string} quizType - Quiz type (official, community, personal)
 * @param {string} levelId - Level ID
 * @param {string} subjectId - Subject ID
 * @param {string} userId - User ID
 * @param {boolean} isPublic - Có công khai không (cho community)
 * @returns {Promise<Object>} Imported quiz
 */
export const importQuizFromGoogleSheet = async (sheetUrl, quizType, levelId, subjectId, userId, isPublic = false) => {
  try {
    // Load questions từ Google Sheet
    const questions = await fetchFromGoogleSheetCSV(sheetUrl);

    if (questions.length === 0) {
      throw new Error('Không tìm thấy câu hỏi nào trong Google Sheet. Vui lòng kiểm tra format.');
    }

    // Get level and subject info
    const { getLevelById } = await import('../models/level.js').catch(() => ({ getLevelById: () => null }));
    const { getSubjectsForLevel } = await import('../models/level.js').catch(() => ({ getSubjectsForLevel: () => [] }));
    
    const level = getLevelById ? getLevelById(levelId) : null;
    const subjects = getSubjectsForLevel ? getSubjectsForLevel(levelId) : [];
    const subject = subjects.find(s => s.id === subjectId);
    const subjectName = subject?.name || subjectId;
    const levelName = level?.name || levelId;

    // Create quiz metadata
    const quizData = createQuizData({
      metadata: createQuizMetadata({
        id: `quiz_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        title: `Bài test ${subjectName}`,
        description: `${levelName} - ${subjectName} - Được import từ Google Sheet`,
        levelId,
        subjectId,
        quizType,
        source: QUIZ_SOURCE_TYPES.GOOGLE_SHEET,
        sourceUrl: sheetUrl,
        questionCount: questions.length,
        creatorId: userId,
        creatorName: userId, // TODO: Get user name
        createdAt: Date.now(),
        updatedAt: Date.now(),
        isPublic: quizType === QUIZ_GROUP_TYPES.COMMUNITY && isPublic,
        isVerified: false,
      }),
      questions,
      cachedAt: Date.now(),
    });

    // Save to database
    await cacheQuiz(quizData);

    return quizData;
  } catch (error) {
    console.error('Error importing quiz from Google Sheet:', error);
    throw error;
  }
};

/**
 * Helper function để build sheet URL
 */
const buildSheetUrl = (sheetId, gid) => {
  return `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv&gid=${gid}`;
};

