/**
 * User Service
 * Quản lý thông tin người dùng và role
 */

import { savePlayer, getAllPlayers } from './storageService.js';

/**
 * User Roles
 */
export const USER_ROLES = {
  STUDENT: 'student',      // Học sinh
  PARENT: 'parent',        // Phụ huynh
  TEACHER: 'teacher',      // Giáo viên
  ADMIN: 'admin',          // Quản trị viên
};

/**
 * Check if user is admin
 * @param {Object} user - User object
 * @returns {boolean}
 */
export const isAdmin = (user) => {
  return user?.role === USER_ROLES.ADMIN;
};

/**
 * Check if user can create quizzes
 * @param {Object} user - User object
 * @returns {boolean}
 */
export const canCreateQuiz = (user) => {
  return user?.role === USER_ROLES.ADMIN || 
         user?.role === USER_ROLES.PARENT || 
         user?.role === USER_ROLES.TEACHER;
};

/**
 * Get current user (from player store)
 * @param {Object} currentPlayer - Current player from store
 * @returns {Object} User object with role
 */
export const getCurrentUser = (currentPlayer) => {
  if (!currentPlayer) return null;
  
  // Default role là PARENT (có thể tạo quiz)
  // TODO: Load role từ database hoặc config
  return {
    id: currentPlayer.id,
    name: currentPlayer.name,
    avatar: currentPlayer.avatar,
    role: currentPlayer.role || USER_ROLES.PARENT,
    email: currentPlayer.email || null,
  };
};

/**
 * Update user role
 * @param {string} userId - User ID
 * @param {string} role - New role
 * @returns {Promise<void>}
 */
export const updateUserRole = async (userId, role) => {
  try {
    const players = await getAllPlayers();
    const user = players.find(p => p.id === userId);
    
    if (user) {
      user.role = role;
      await savePlayer(user);
    }
  } catch (error) {
    console.error('Error updating user role:', error);
    throw error;
  }
};

