import React, { useEffect, useState } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useLevelStore } from '../store/levelStore';
import { loadSubjectsForLevel } from '../services/levelService.js';
import { getSubjectStatsMap } from '../services/quizStatsService.js';
import { soundService } from '../services/soundService';
import { formatCompactNumber, formatRatingValue } from '../utils/numberFormat.js';
import { ScreenContainer, Header, SubjectCard, BackButton } from '../components/screen';

/**
 * SubjectSelectScreen Component
 * Màn hình chọn môn học trong cấp độ đã chọn
 */
export const SubjectSelectScreen = () => {
  const { goToNext } = useFlowStore();
  const { currentLevel, setCurrentSubject } = useLevelStore();
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [subjectStats, setSubjectStats] = useState({});
  const [statsLoading, setStatsLoading] = useState(true);

  useEffect(() => {
    if (currentLevel) {
      loadSubjectsData();
      loadSubjectsStats(currentLevel.id);
    }
  }, [currentLevel]);

  const loadSubjectsData = async () => {
    try {
      setLoading(true);
      const loadedSubjects = await loadSubjectsForLevel(currentLevel.id);
      setSubjects(loadedSubjects);
    } catch (error) {
      console.error('Error loading subjects:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadSubjectsStats = async (levelId) => {
    try {
      setStatsLoading(true);
      const stats = await getSubjectStatsMap(levelId);
      setSubjectStats(stats || {});
    } catch (error) {
      console.error('Error loading subject stats:', error);
    } finally {
      setStatsLoading(false);
    }
  };

  const handleSelectSubject = (subject) => {
    soundService.playClick();
    setCurrentSubject(subject);
    goToNext('quizTypeSelect');
  };

  if (!currentLevel) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Chưa chọn cấp độ!</p>
          <BackButton onClick={() => goToNext('levelSelect')} />
        </div>
      </ScreenContainer>
    );
  }

  if (loading) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4 animate-spin">⏳</div>
          <p className="text-xl text-gray-600">Đang tải môn học...</p>
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <BackButton
        inline
        variant="ghost"
        label="← Quay lại"
        onClick={() => goToNext('levelSelect')}
        className="mb-2"
      />
      <Header
        title="Chọn môn học"
        subtitle={`Cấp độ: ${currentLevel.name}`}
        titleClassName="text-4xl"
      />

      <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
        {subjects.map((subject, index) => {
          const stats = subjectStats[subject.id] || {};
          const statItems = [
            { label: 'Bài test', value: statsLoading ? '…' : formatCompactNumber(stats.quizCount) },
            { label: 'Lượt làm', value: statsLoading ? '…' : formatCompactNumber(stats.totalUsage) },
            { label: 'Người học', value: statsLoading ? '…' : formatCompactNumber(stats.playerCount) },
            { label: 'Đánh giá', value: statsLoading ? '…' : formatRatingValue(stats.averageRating) },
          ];

          return (
            <SubjectCard
              key={subject.id}
              icon={subject.icon}
              title={subject.name}
              description={subject.description || ''}
              onClick={() => handleSelectSubject(subject)}
              delay={index * 0.1}
              stats={statItems}
            />
          );
        })}
      </div>

    </ScreenContainer>
  );
};
