import React, { useEffect, useState } from 'react';
import { useFlowStore } from '../store/flowStore';
import { usePlayerStore } from '../store/playerStore';
import { getPlayerResults } from '../services/storageService';
import { calculateStats } from '../services/badgeService';
import { soundService } from '../services/soundService';
import { getCurrentUser, canCreateQuiz, USER_ROLES } from '../services/userService';
import { ScreenContainer, Header, StatsCard, ActionButton } from '../components/screen';
import { MenuOverlay, MenuButton } from '../components/menu';

/**
 * HomeScreen Component
 * Màn hình chính với menu và thống kê
 * Refactored to use theme and screen components
 */
export const HomeScreen = () => {
  const { goToNext } = useFlowStore();
  const { currentPlayer } = usePlayerStore();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [stats, setStats] = useState({
    totalQuizzes: 0,
    averageScore: 0,
    highestScore: 0,
  });

  useEffect(() => {
    if (currentPlayer) {
      loadStats();
    }
  }, [currentPlayer]);

  const loadStats = async () => {
    try {
      const results = await getPlayerResults(currentPlayer.id);
      const calculatedStats = calculateStats(results);
      setStats(calculatedStats);
    } catch (error) {
      console.error('Error loading stats:', error);
    }
  };

  const handleStartQuiz = () => {
    soundService.playClick();
    goToNext('levelSelect');
  };

  const handleFilterQuiz = () => {
    soundService.playClick();
    goToNext('quizFilter');
  };

  const handleImportQuiz = () => {
    soundService.playClick();
    goToNext('importQuiz');
  };

  const handleViewStats = () => {
    soundService.playClick();
    // TODO: Implement stats screen
    alert('Tính năng thống kê đang phát triển!');
  };

  const handleSettings = () => {
    soundService.playClick();
    goToNext('settings');
  };

  const handleToggleMenu = () => {
    soundService.playClick();
    setIsMenuOpen(!isMenuOpen);
  };

  const handleCloseMenu = () => {
    setIsMenuOpen(false);
  };

  // Get current user và menu items dựa trên role
  const user = getCurrentUser(currentPlayer);
  const canCreate = canCreateQuiz(user);

  // Menu items - chỉ hiển thị các tính năng phù hợp với role
  const menuItems = [];

  // Tính năng cho phụ huynh/giáo viên/admin
  if (canCreate) {
    menuItems.push({
      id: 'importQuiz',
      icon: '📥',
      title: 'Tạo bài test',
      description: 'Import từ Google Sheet',
      onClick: handleImportQuiz,
    });
  }

  // Tính năng cho tất cả
  menuItems.push({
    id: 'stats',
    icon: '📊',
    title: 'Xem thống kê',
    description: 'Xem kết quả học tập',
    onClick: handleViewStats,
  });

  menuItems.push({
    id: 'settings',
    icon: '⚙️',
    title: 'Cài đặt',
    description: 'Cài đặt ứng dụng',
    onClick: handleSettings,
  });

  // Thêm role indicator nếu không phải học sinh
  if (user && user.role !== USER_ROLES.STUDENT) {
    menuItems.push({
      id: 'role',
      icon: user.role === USER_ROLES.ADMIN ? '👑' : user.role === USER_ROLES.TEACHER ? '👩‍🏫' : '👨‍👩‍👧',
      title: `Vai trò: ${user.role === USER_ROLES.ADMIN ? 'Quản trị viên' : user.role === USER_ROLES.TEACHER ? 'Giáo viên' : 'Phụ huynh'}`,
      description: 'Thông tin tài khoản',
      onClick: null,
      disabled: true,
    });
  }

  return (
    <>
      <ScreenContainer>
        <Header
          title={`👋 Xin chào, ${currentPlayer?.name || 'Bạn'}!`}
          subtitle="Sẵn sàng học tập chưa?"
        />

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
          <StatsCard
            icon="📚"
            value={stats.totalQuizzes}
            label="Bài đã làm"
            valueColor="text-primary-600"
          />
          <StatsCard
            icon="⭐"
            value={stats.averageScore}
            label="Điểm trung bình"
            valueColor="text-yellow-600"
          />
          <StatsCard
            icon="🏆"
            value={stats.highestScore}
            label="Điểm cao nhất"
            valueColor="text-green-600"
          />
        </div>

        {/* Chỉ hiển thị nút chính cho học sinh */}
        <div className="space-y-4">
          <ActionButton
            onClick={handleStartQuiz}
            variant="primary"
            size="lg"
            delay={0.2}
            className="w-full"
          >
            🎮 Bắt đầu làm bài
          </ActionButton>
          <ActionButton
            onClick={handleFilterQuiz}
            variant="outline"
            size="lg"
            delay={0.3}
            className="w-full"
          >
            🔍 Tìm kiếm bài test
          </ActionButton>
        </div>
      </ScreenContainer>

      {/* Menu Button - Floating */}
      <MenuButton onClick={handleToggleMenu} />

      {/* Menu Overlay */}
      <MenuOverlay
        isOpen={isMenuOpen}
        onClose={handleCloseMenu}
        items={menuItems}
      />
    </>
  );
};

