import React, { useState, useEffect } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { soundService } from '../services/soundService';
import { loadAllQuestions, loadQuestionsForSubject } from '../services/googleSheetService';
// Fallback imports
import mathQuestionsFallback from '../data/questions-math-grade3.json';
import vietnameseQuestionsFallback from '../data/questions-vietnamese-grade3.json';
import englishQuestionsFallback from '../data/questions-english-mover.json';
import { shuffleArray } from '../utils';
import { ScreenContainer, Header, SubjectCard, BackButton } from '../components/screen';

/**
 * LessonSelectScreen Component
 * Màn hình chọn môn học
 * Refactored to use theme and screen components
 * Now loads questions from Google Sheets
 */
export const LessonSelectScreen = () => {
  const { goToNext } = useFlowStore();
  const { setCurrentLesson } = useQuizStore();
  const [questions, setQuestions] = useState({
    math: [],
    vietnamese: [],
    english: [],
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Load questions khi component mount
  useEffect(() => {
    loadQuestions();
  }, []);

  const loadQuestions = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Load từ Google Sheets hoặc fallback
      const loadedQuestions = await loadAllQuestions();
      
      // Nếu không load được từ Google Sheets, dùng fallback
      if (!loadedQuestions.math || loadedQuestions.math.length === 0) {
        console.warn('Using fallback JSON data');
        setQuestions({
          math: mathQuestionsFallback,
          vietnamese: vietnameseQuestionsFallback,
          english: englishQuestionsFallback,
        });
      } else {
        setQuestions(loadedQuestions);
      }
    } catch (err) {
      console.error('Error loading questions:', err);
      setError(err.message);
      // Fallback về JSON local
      setQuestions({
        math: mathQuestionsFallback,
        vietnamese: vietnameseQuestionsFallback,
        english: englishQuestionsFallback,
      });
    } finally {
      setLoading(false);
    }
  };

  const subjects = [
    { id: 'math', name: 'Toán', description: 'Toán lớp 3', icon: '🔢' },
    { id: 'vietnamese', name: 'Tiếng Việt', description: 'Tiếng Việt lớp 3', icon: '📝' },
    { id: 'english', name: 'Tiếng Anh', description: 'Tiếng Anh Mover', icon: '🇬🇧' },
    { id: 'mixed', name: 'Tổng hợp', description: 'Tất cả các môn', icon: '🎯' },
  ];

  const handleSelectSubject = async (subject) => {
    soundService.playClick();
    
    try {
      let subjectQuestions;
      
      if (subject.id === 'mixed') {
        // Trộn tất cả câu hỏi từ 3 môn
        const allQuestions = [
          ...questions.math,
          ...questions.vietnamese,
          ...questions.english,
        ];
        subjectQuestions = shuffleArray(allQuestions);
      } else {
        // Load lại từ Google Sheet nếu cần (hoặc dùng cached)
        if (questions[subject.id] && questions[subject.id].length > 0) {
          subjectQuestions = questions[subject.id];
        } else {
          // Try to load on demand
          subjectQuestions = await loadQuestionsForSubject(subject.id);
          if (subjectQuestions.length === 0) {
            // Use fallback
            const fallbacks = {
              math: mathQuestionsFallback,
              vietnamese: vietnameseQuestionsFallback,
              english: englishQuestionsFallback,
            };
            subjectQuestions = fallbacks[subject.id] || [];
          }
        }
      }
      
      if (subjectQuestions.length === 0) {
        alert('Không có câu hỏi nào cho môn này!');
        return;
      }
      
      setCurrentLesson({
        id: subject.id,
        name: subject.name,
        description: subject.description,
        icon: subject.icon,
        questions: subjectQuestions,
      });
      
      goToNext('questionCount');
    } catch (error) {
      console.error('Error loading subject:', error);
      alert('Có lỗi khi tải câu hỏi. Vui lòng thử lại!');
    }
  };

  if (loading) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4 animate-spin">⏳</div>
          <p className="text-xl text-gray-600">Đang tải câu hỏi...</p>
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <Header
        title="Chọn môn học"
        titleClassName="text-4xl"
      />

      {error && (
        <div className="mb-4 p-4 bg-yellow-50 border border-yellow-200 rounded-xl text-yellow-800 text-sm">
          ⚠️ {error} - Đang sử dụng dữ liệu local
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {subjects.map((subject, index) => {
          const questionCount = subject.id === 'mixed'
            ? questions.math.length + questions.vietnamese.length + questions.english.length
            : questions[subject.id]?.length || 0;
          
          return (
            <SubjectCard
              key={subject.id}
              icon={subject.icon}
              title={subject.name}
              description={`${subject.description} (${questionCount} câu hỏi)`}
              onClick={() => handleSelectSubject(subject)}
              delay={index * 0.1}
            />
          );
        })}
      </div>

      <BackButton onClick={() => goToNext('home')} />
    </ScreenContainer>
  );
};

