import React, { useEffect, useState } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useLevelStore } from '../store/levelStore';
import { loadLevels } from '../services/levelService.js';
import { getLevelStatsMap } from '../services/quizStatsService.js';
import { soundService } from '../services/soundService';
import { formatCompactNumber, formatRatingValue } from '../utils/numberFormat.js';
import { ScreenContainer, Header, SubjectCard, BackButton } from '../components/screen';

/**
 * LevelSelectScreen Component
 * Màn hình chọn cấp độ giáo dục
 */
export const LevelSelectScreen = () => {
  const { goToNext } = useFlowStore();
  const { setCurrentLevel } = useLevelStore();
  const [levels, setLevels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [levelStats, setLevelStats] = useState({});
  const [statsLoading, setStatsLoading] = useState(true);

  useEffect(() => {
    loadLevelsData();
    loadLevelStats();
  }, []);

  const loadLevelsData = async () => {
    try {
      const loadedLevels = await loadLevels();
      setLevels(loadedLevels);
    } catch (error) {
      console.error('Error loading levels:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadLevelStats = async () => {
    try {
      setStatsLoading(true);
      const stats = await getLevelStatsMap();
      setLevelStats(stats || {});
    } catch (error) {
      console.error('Error loading level stats:', error);
    } finally {
      setStatsLoading(false);
    }
  };

  const handleSelectLevel = (level) => {
    soundService.playClick();
    setCurrentLevel(level);
    goToNext('subjectSelect');
  };

  if (loading) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4 animate-spin">⏳</div>
          <p className="text-xl text-gray-600">Đang tải...</p>
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <BackButton
        inline
        variant="ghost"
        label="← Quay lại"
        onClick={() => goToNext('home')}
        className="mb-2"
      />
      <Header
        title="Chọn cấp độ"
        subtitle="Chọn cấp độ phù hợp với bạn"
        titleClassName="text-4xl"
      />

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {levels.map((level, index) => {
          const stats = levelStats[level.id] || {};
          const statItems = [
            { label: 'Bài test', value: statsLoading ? '…' : formatCompactNumber(stats.quizCount) },
            { label: 'Lượt làm', value: statsLoading ? '…' : formatCompactNumber(stats.totalUsage) },
            { label: 'Người học', value: statsLoading ? '…' : formatCompactNumber(stats.playerCount) },
            { label: 'Đánh giá', value: statsLoading ? '…' : formatRatingValue(stats.averageRating) },
          ];

          return (
            <SubjectCard
              key={level.id}
              icon={level.icon}
              title={level.name}
              description={level.description}
              onClick={() => handleSelectLevel(level)}
              delay={index * 0.05}
              className="h-full"
              stats={statItems}
            />
          );
        })}
      </div>

    </ScreenContainer>
  );
};



