import React from 'react';
import { motion } from 'framer-motion';
import { Card } from '../Card';
import { cn } from '../../utils';

/**
 * PlayerCard Component
 * Card for displaying player selection
 */
export const PlayerCard = ({
  avatar,
  name,
  onClick,
  delay = 0,
  className = '',
  ...props
}) => {
  return (
    <motion.div
      initial={{ opacity: 0, x: -20 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay }}
      {...props}
    >
      <Card
        onClick={onClick}
        className={cn('text-center cursor-pointer group relative overflow-hidden', className)}
      >
        {/* Hover gradient effect */}
        <div className="absolute inset-0 bg-gradient-to-br from-primary-500/0 to-secondary-500/0 group-hover:from-primary-500/10 group-hover:to-secondary-500/10 transition-all duration-300" />
        
        <div className="relative z-10">
          {avatar && (
            <motion.div
              className="text-6xl mb-4 transform group-hover:scale-110 transition-transform duration-300"
              whileHover={{ rotate: 360 }}
              transition={{ duration: 0.6 }}
            >
              {avatar}
            </motion.div>
          )}
          {name && (
            <h3 className="text-xl font-semibold text-gray-800 group-hover:text-primary-600 transition-colors duration-300">
              {name}
            </h3>
          )}
        </div>
      </Card>
    </motion.div>
  );
};

