/**
 * Google Sheets Configuration
 * Cấu hình các Google Sheets URLs cho từng môn học
 * 
 * Cách lấy URL:
 * 1. Mở Google Sheet
 * 2. File > Share > Publish to web > Chọn "Comma-separated values (.csv)"
 * 3. Copy link và paste vào đây
 * 
 * Hoặc sử dụng format:
 * https://docs.google.com/spreadsheets/d/{SHEET_ID}/export?format=csv&gid={GID}
 */

export const sheetsConfig = {
  math: {
    // URL Google Sheet cho Toán
    // Thay bằng URL thực tế của bạn
    url: import.meta.env.VITE_SHEET_MATH_URL || '',
    // Hoặc dùng Sheet ID và GID
    sheetId: import.meta.env.VITE_SHEET_MATH_ID || '',
    gid: import.meta.env.VITE_SHEET_MATH_GID || '0',
    // Fallback về JSON local nếu không có URL
    fallback: '/src/data/questions-math-grade3.json',
  },
  vietnamese: {
    url: import.meta.env.VITE_SHEET_VIETNAMESE_URL || '',
    sheetId: import.meta.env.VITE_SHEET_VIETNAMESE_ID || '',
    gid: import.meta.env.VITE_SHEET_VIETNAMESE_GID || '0',
    fallback: '/src/data/questions-vietnamese-grade3.json',
  },
  english: {
    url: import.meta.env.VITE_SHEET_ENGLISH_URL || '',
    sheetId: import.meta.env.VITE_SHEET_ENGLISH_ID || '',
    gid: import.meta.env.VITE_SHEET_ENGLISH_GID || '0',
    fallback: '/src/data/questions-english-mover.json',
  },
};

/**
 * Helper function để build Google Sheets CSV URL từ Sheet ID và GID
 */
export const buildSheetUrl = (sheetId, gid = '0') => {
  if (!sheetId) return null;
  return `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv&gid=${gid}`;
};

/**
 * Helper function để build Google Sheets published CSV URL
 * (Nếu sheet đã được publish to web)
 */
export const buildPublishedSheetUrl = (sheetId, sheetName = 'Sheet1') => {
  if (!sheetId) return null;
  return `https://docs.google.com/spreadsheets/d/${sheetId}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(sheetName)}`;
};

