import React from 'react';
import { motion } from 'framer-motion';
import { Card } from '../Card';
import { cn } from '../../utils';

/**
 * SettingCard Component
 * Card for displaying setting options with title and description
 */
export const SettingCard = ({
  title,
  description,
  selected = false,
  onClick,
  className = '',
  ...props
}) => {
  return (
    <motion.button
      onClick={onClick}
      className={cn(
        'w-full p-4 rounded-xl border-2 transition-all duration-300 text-left shadow-sm',
        selected
          ? 'border-primary-600 bg-gradient-to-br from-primary-50 to-primary-100 shadow-md shadow-primary-200/50'
          : 'border-gray-300 bg-white hover:border-primary-400 hover:bg-primary-50/30 hover:shadow-md',
        className
      )}
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      {...props}
    >
      <div className={cn(
        'font-semibold',
        selected ? 'text-primary-700' : 'text-gray-800'
      )}>
        {title}
      </div>
      {description && (
        <div className={cn(
          'text-sm mt-1',
          selected ? 'text-primary-600' : 'text-gray-600'
        )}>
          {description}
        </div>
      )}
    </motion.button>
  );
};

