/**
 * Sound Service
 * Quản lý hiệu ứng âm thanh (đúng/sai, hoàn thành)
 */

class SoundService {
  constructor() {
    this.audioContext = null;
    this.sounds = {};
    this.enabled = true;
    this.volume = 0.7;
  }

  /**
   * Khởi tạo AudioContext
   */
  init() {
    try {
      this.audioContext = new (window.AudioContext || window.webkitAudioContext)();
      // Resume AudioContext sau user gesture để tránh warning
      if (this.audioContext.state === 'suspended') {
        const resumeAudio = () => {
          this.audioContext.resume().catch(() => {});
        };
        document.addEventListener('click', resumeAudio, { once: true });
        document.addEventListener('touchstart', resumeAudio, { once: true });
      }
    } catch (error) {
      console.warn('Web Audio API not supported:', error);
    }
  }

  /**
   * Tạo âm thanh đơn giản bằng Web Audio API
   * @param {number} frequency - Tần số (Hz)
   * @param {number} duration - Thời lượng (ms)
   * @param {string} type - Loại sóng: 'sine', 'square', 'sawtooth', 'triangle'
   */
  playTone(frequency, duration = 200, type = 'sine') {
    if (!this.enabled || !this.audioContext) return;

    // Resume AudioContext nếu đang suspended
    if (this.audioContext.state === 'suspended') {
      this.audioContext.resume().catch(() => {});
    }

    try {
      const oscillator = this.audioContext.createOscillator();
      const gainNode = this.audioContext.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(this.audioContext.destination);

      oscillator.frequency.value = frequency;
      oscillator.type = type;

      gainNode.gain.setValueAtTime(0, this.audioContext.currentTime);
      gainNode.gain.linearRampToValueAtTime(this.volume, this.audioContext.currentTime + 0.01);
      gainNode.gain.exponentialRampToValueAtTime(0.01, this.audioContext.currentTime + duration / 1000);

      oscillator.start(this.audioContext.currentTime);
      oscillator.stop(this.audioContext.currentTime + duration / 1000);
    } catch (error) {
      console.warn('Error playing tone:', error);
    }
  }

  /**
   * Phát âm thanh "đúng"
   */
  playCorrect() {
    // Chuỗi nốt nhạc vui tươi
    this.playTone(523.25, 100, 'sine'); // C5
    setTimeout(() => this.playTone(659.25, 100, 'sine'), 100); // E5
    setTimeout(() => this.playTone(783.99, 150, 'sine'), 200); // G5
  }

  /**
   * Phát âm thanh "sai"
   */
  playIncorrect() {
    // Nốt thấp, buồn
    this.playTone(200, 300, 'sawtooth');
  }

  /**
   * Phát âm thanh "hoàn thành"
   */
  playComplete() {
    // Chuỗi nốt nhạc chiến thắng
    this.playTone(523.25, 150, 'sine'); // C5
    setTimeout(() => this.playTone(659.25, 150, 'sine'), 150); // E5
    setTimeout(() => this.playTone(783.99, 150, 'sine'), 300); // G5
    setTimeout(() => this.playTone(1046.50, 300, 'sine'), 450); // C6
  }

  /**
   * Phát âm thanh "click"
   */
  playClick() {
    this.playTone(800, 50, 'square');
  }

  /**
   * Phát âm thanh "badge"
   */
  playBadge() {
    // Chuỗi nốt nhạc đặc biệt cho badge
    this.playTone(659.25, 100, 'sine'); // E5
    setTimeout(() => this.playTone(783.99, 100, 'sine'), 100); // G5
    setTimeout(() => this.playTone(987.77, 200, 'sine'), 200); // B5
  }

  /**
   * Phát âm thanh "error"
   */
  playError() {
    // Nốt thấp, cảnh báo
    this.playTone(150, 400, 'sawtooth');
  }

  /**
   * Phát âm thanh "success"
   */
  playSuccess() {
    // Chuỗi nốt nhạc thành công
    this.playTone(523.25, 100, 'sine'); // C5
    setTimeout(() => this.playTone(659.25, 100, 'sine'), 100); // E5
    setTimeout(() => this.playTone(783.99, 200, 'sine'), 200); // G5
  }

  /**
   * Bật/tắt âm thanh
   * @param {boolean} enabled - Bật hoặc tắt
   */
  setEnabled(enabled) {
    this.enabled = enabled;
  }

  /**
   * Đặt âm lượng
   * @param {number} volume - Âm lượng từ 0 đến 1
   */
  setVolume(volume) {
    this.volume = Math.max(0, Math.min(1, volume));
  }
}

// Export singleton instance
export const soundService = new SoundService();

// Khởi tạo khi module được load
if (typeof window !== 'undefined') {
  soundService.init();
}

