/**
 * Quiz Stats Service
 * Tính toán thống kê cho Level → Subject → Quiz Type
 */

import { getAllCachedQuizzes, getAllQuizResults } from './storageService.js';

const STATS_CACHE_TTL = 5 * 1000; // 5 giây
let statsCache = null;
let cacheTimestamp = 0;

const ensureStatsData = async () => {
  const now = Date.now();
  if (statsCache && now - cacheTimestamp < STATS_CACHE_TTL) {
    return statsCache;
  }

  const [quizzes, results] = await Promise.all([
    getAllCachedQuizzes(),
    getAllQuizResults(),
  ]);

  const resultIndex = new Map();
  results.forEach(result => {
    if (!result?.quizId) return;
    if (!resultIndex.has(result.quizId)) {
      resultIndex.set(result.quizId, []);
    }
    resultIndex.get(result.quizId).push(result);
  });

  statsCache = { quizzes, resultIndex };
  cacheTimestamp = now;
  return statsCache;
};

const createAccumulator = () => ({
  quizCount: 0,
  totalUsage: 0,
  playerIds: new Set(),
  ratingTotal: 0,
  ratingVotes: 0,
});

const accumulateStats = (acc, quiz, quizResults = []) => {
  acc.quizCount += 1;
  acc.totalUsage += quiz?.usageCount || 0;

  const rating = Number(quiz?.rating || 0);
  const ratingCount = Number(quiz?.ratingCount || 0);

  if (ratingCount > 0 && rating > 0) {
    acc.ratingTotal += rating * ratingCount;
    acc.ratingVotes += ratingCount;
  } else if (rating > 0) {
    acc.ratingTotal += rating;
    acc.ratingVotes += 1;
  }

  quizResults.forEach(result => {
    if (result?.playerId) {
      acc.playerIds.add(result.playerId);
    }
  });
};

const finalizeStats = (acc = createAccumulator()) => ({
  quizCount: acc.quizCount,
  totalUsage: acc.totalUsage,
  playerCount: acc.playerIds.size,
  averageRating:
    acc.ratingVotes > 0
      ? Number((acc.ratingTotal / acc.ratingVotes).toFixed(1))
      : 0,
});

const buildKey = (quiz, field) => {
  return quiz?.[field] || quiz?.[field === 'quizType' ? 'group' : field === 'subjectId' ? 'subject' : field === 'levelId' ? 'level' : field];
};

/**
 * Lấy thống kê theo level
 * @returns {Promise<Record<string, Stats>>}
 */
export const getLevelStatsMap = async () => {
  const { quizzes, resultIndex } = await ensureStatsData();
  const statsByLevel = {};

  quizzes.forEach(quiz => {
    const levelId = buildKey(quiz, 'levelId');
    if (!levelId) return;
    if (!statsByLevel[levelId]) {
      statsByLevel[levelId] = createAccumulator();
    }
    accumulateStats(statsByLevel[levelId], quiz, resultIndex.get(quiz.id));
  });

  return Object.keys(statsByLevel).reduce((acc, levelId) => {
    acc[levelId] = finalizeStats(statsByLevel[levelId]);
    return acc;
  }, {});
};

/**
 * Lấy thống kê cho các môn của một level
 * @param {string} levelId
 * @returns {Promise<Record<string, Stats>>}
 */
export const getSubjectStatsMap = async (levelId) => {
  const { quizzes, resultIndex } = await ensureStatsData();
  const statsBySubject = {};

  quizzes.forEach(quiz => {
    const quizLevelId = buildKey(quiz, 'levelId');
    if (levelId && quizLevelId !== levelId) return;

    const subjectId = buildKey(quiz, 'subjectId');
    if (!subjectId) return;

    if (!statsBySubject[subjectId]) {
      statsBySubject[subjectId] = createAccumulator();
    }
    accumulateStats(statsBySubject[subjectId], quiz, resultIndex.get(quiz.id));
  });

  return Object.keys(statsBySubject).reduce((acc, subjectId) => {
    acc[subjectId] = finalizeStats(statsBySubject[subjectId]);
    return acc;
  }, {});
};

/**
 * Lấy thống kê theo loại quiz cho một level + subject
 * @param {string} levelId
 * @param {string} subjectId
 * @returns {Promise<Record<string, Stats>>}
 */
export const getQuizTypeStatsMap = async (levelId, subjectId) => {
  const { quizzes, resultIndex } = await ensureStatsData();
  const statsByType = {};

  quizzes.forEach(quiz => {
    const quizLevelId = buildKey(quiz, 'levelId');
    const quizSubjectId = buildKey(quiz, 'subjectId');

    if (levelId && quizLevelId !== levelId) return;
    if (subjectId && quizSubjectId !== subjectId) return;

    const quizType = buildKey(quiz, 'quizType');
    if (!quizType) return;

    if (!statsByType[quizType]) {
      statsByType[quizType] = createAccumulator();
    }
    accumulateStats(statsByType[quizType], quiz, resultIndex.get(quiz.id));
  });

  return Object.keys(statsByType).reduce((acc, quizType) => {
    acc[quizType] = finalizeStats(statsByType[quizType]);
    return acc;
  }, {});
};

/**
 * Force refresh stats cache (sau khi import quiz mới)
 */
export const invalidateQuizStatsCache = () => {
  statsCache = null;
  cacheTimestamp = 0;
};


