import React, { useState, useEffect, useRef, useMemo } from 'react';
import { AnimatePresence } from 'framer-motion';
import { Button } from '../components/Button';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { calculateScore } from '../services/scoringService';
import { shuffleArray } from '../utils';
import { soundService } from '../services/soundService';
import { ScreenContainer } from '../components/screen';
import { QuizHeader, QuestionCard, ChoiceButton, InputAnswer } from '../components/quiz';

/**
 * QuizScreen Component
 * Màn hình làm bài quiz
 */
export const QuizScreen = () => {
  console.log('QuizScreen component rendered!');
  const { goToNext } = useFlowStore();
  const { currentLesson, questionCount, quizSettings, setQuizResult, setQuestionCount } = useQuizStore();
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState('');
  const [userAnswers, setUserAnswers] = useState([]);
  const [timeRemaining, setTimeRemaining] = useState(quizSettings?.timeLimit || 0);
  const [isAnswered, setIsAnswered] = useState(false);
  const timerRef = useRef(null);

  // Đảm bảo questionCount có giá trị mặc định
  useEffect(() => {
    if (!questionCount && currentLesson?.questions) {
      const defaultCount = Math.min(10, currentLesson.questions.length);
      setQuestionCount(defaultCount);
      console.log('Setting default questionCount:', defaultCount);
    }
  }, [questionCount, currentLesson, setQuestionCount]);

  const questions = currentLesson?.questions || [];
  
  // Chỉ shuffle một lần khi component mount hoặc khi lesson thay đổi
  // Và chỉ lấy số lượng câu hỏi đã chọn
  const shuffledQuestions = useMemo(() => {
    console.log('Shuffling questions:', {
      questionsLength: questions.length,
      questionCount,
      hasCurrentLesson: !!currentLesson
    });
    
    if (!questions || questions.length === 0) {
      console.warn('No questions available');
      return [];
    }
    
    const shuffled = shuffleArray([...questions]);
    const count = questionCount || 10;
    const result = shuffled.slice(0, Math.min(count, shuffled.length));
    console.log('Shuffled result:', result.length, 'questions');
    return result;
  }, [currentLesson?.id, questions.length, questionCount]); // Shuffle lại khi lesson hoặc questionCount thay đổi
  
  const currentQuestion = shuffledQuestions && shuffledQuestions.length > 0 
    ? shuffledQuestions[currentQuestionIndex] 
    : null;
  
  // Reset currentQuestionIndex khi lesson hoặc questionCount thay đổi
  useEffect(() => {
    setCurrentQuestionIndex(0);
    setSelectedAnswer('');
    setIsAnswered(false);
    setUserAnswers([]);
    setTimeRemaining(quizSettings?.timeLimit || 0);
  }, [currentLesson?.id, questionCount]);

  // Chỉ shuffle choices một lần cho mỗi câu hỏi
  const shuffledChoices = useMemo(() => {
    if (!currentQuestion?.choices) return [];
    return shuffleArray([...currentQuestion.choices]);
  }, [currentQuestionIndex, currentQuestion?.id]); // Chỉ shuffle lại khi chuyển câu hỏi

  useEffect(() => {
    // Reset selectedAnswer khi chuyển câu hỏi
    setSelectedAnswer('');
    setIsAnswered(false);
    
    if (quizSettings?.timeLimit > 0 && !isAnswered) {
      timerRef.current = setInterval(() => {
        setTimeRemaining((prev) => {
          if (prev <= 1) {
            handleAnswer('');
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }

    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [currentQuestionIndex]);

  const handleAnswer = (answer) => {
    if (isAnswered) return;

    setIsAnswered(true);
    // Normalize answer để so sánh (trim whitespace, lowercase)
    const normalizedUserAnswer = answer.trim().toLowerCase();
    const normalizedCorrectAnswer = currentQuestion.answer.trim().toLowerCase();
    const isCorrect = normalizedUserAnswer === normalizedCorrectAnswer;
    
    if (isCorrect) {
      soundService.playCorrect();
    } else {
      soundService.playIncorrect();
    }

    const answerData = {
      questionId: currentQuestion.id,
      question: currentQuestion.question,
      userAnswer: answer,
      correctAnswer: currentQuestion.answer,
      isCorrect,
      timeRemaining: timeRemaining,
      maxTime: quizSettings?.timeLimit || 0,
    };

    setUserAnswers([...userAnswers, answerData]);

    // Chuyển câu hỏi tiếp theo sau 1.5 giây
    setTimeout(() => {
      if (currentQuestionIndex < shuffledQuestions.length - 1) {
        // Reset state trước khi chuyển câu
        setSelectedAnswer('');
        setIsAnswered(false);
        setTimeRemaining(quizSettings?.timeLimit || 0);
        // Chuyển câu hỏi sau khi reset state
        setCurrentQuestionIndex(prev => prev + 1);
      } else {
        finishQuiz();
      }
    }, 1500);
  };

  const finishQuiz = () => {
    const correctAnswers = userAnswers.filter((a) => a.isCorrect).length + 
      (selectedAnswer === currentQuestion.answer ? 1 : 0);
    const totalQuestions = shuffledQuestions.length;

    const answers = [...userAnswers];
    if (selectedAnswer) {
      answers.push({
        questionId: currentQuestion.id,
        question: currentQuestion.question,
        userAnswer: selectedAnswer,
        correctAnswer: currentQuestion.answer,
        isCorrect: selectedAnswer === currentQuestion.answer,
        timeRemaining: timeRemaining,
        maxTime: quizSettings?.timeLimit || 0,
      });
    }

    const score = calculateScore(quizSettings?.scoringMode || 'basic', {
      correctAnswers,
      totalQuestions,
      answers,
    });

    setQuizResult({
      score,
      totalQuestions,
      correctAnswers,
      answers,
      questions: shuffledQuestions,
    });

    soundService.playComplete();
    goToNext('result');
  };

  // Early return check với log
  if (!currentLesson || !currentLesson.questions || currentLesson.questions.length === 0) {
    console.log('QuizScreen: No lesson or questions', {
      hasCurrentLesson: !!currentLesson,
      hasQuestions: !!currentLesson?.questions,
      questionsLength: currentLesson?.questions?.length
    });
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Không có câu hỏi nào!</p>
          <Button onClick={() => goToNext('lessonSelect')} variant="primary">
            Quay lại chọn môn
          </Button>
        </div>
      </ScreenContainer>
    );
  }

  // Debug: Log để kiểm tra
  useEffect(() => {
    console.log('QuizScreen Debug:', {
      hasCurrentLesson: !!currentLesson,
      questionsCount: questions.length,
      shuffledCount: shuffledQuestions?.length || 0,
      questionCount,
      currentQuestionIndex,
      hasCurrentQuestion: !!currentQuestion
    });
  }, [currentLesson, questions.length, shuffledQuestions?.length, questionCount, currentQuestionIndex, currentQuestion]);

  if (!currentQuestion || !shuffledQuestions || shuffledQuestions.length === 0) {
    console.log('QuizScreen: No current question or shuffled questions', {
      hasCurrentQuestion: !!currentQuestion,
      shuffledLength: shuffledQuestions?.length || 0,
      currentQuestionIndex,
      questionCount
    });
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Đang tải câu hỏi...</p>
          <p className="text-sm text-gray-500">
            {!currentLesson ? 'Chưa chọn môn học' : 
             !shuffledQuestions || shuffledQuestions.length === 0 ? 'Không có câu hỏi' : 
             'Đang xử lý...'}
          </p>
          <p className="text-xs text-gray-400 mt-2">
            Debug: shuffled={shuffledQuestions?.length || 0}, idx={currentQuestionIndex}, count={questionCount}
          </p>
          <Button 
            onClick={() => goToNext('lessonSelect')} 
            variant="outline" 
            className="mt-4"
          >
            Quay lại
          </Button>
        </div>
      </ScreenContainer>
    );
  }

  const isInputCorrect = selectedAnswer.trim().toLowerCase() === currentQuestion.answer.trim().toLowerCase();

  return (
    <ScreenContainer maxWidth="3xl">
      <QuizHeader
        currentIndex={currentQuestionIndex}
        totalQuestions={shuffledQuestions.length}
        timeRemaining={timeRemaining}
        timeLimit={quizSettings?.timeLimit || 0}
      />

      <AnimatePresence mode="wait">
        <QuestionCard
          key={currentQuestionIndex}
          question={currentQuestion.question}
          questionNumber={currentQuestionIndex + 1}
          hint={currentQuestion.hint}
          imageUrl={currentQuestion.imageUrl}
          explanation={currentQuestion.explanation}
          showExplanation={isAnswered}
        >
          {currentQuestion.type === 'choice' ? (
            <div className="space-y-4">
              <div
                className="grid gap-3"
                style={{
                  gridTemplateColumns: `repeat(${Math.max(shuffledChoices.length || 1, 1)}, minmax(0, 1fr))`,
                }}
              >
                {shuffledChoices.map((choice, index) => {
                  const isSelected = selectedAnswer === choice;
                  const isCorrect = choice === currentQuestion.answer;

                  return (
                    <ChoiceButton
                      key={index}
                      choice={choice}
                      isSelected={isSelected}
                      isCorrect={isCorrect}
                      isAnswered={isAnswered}
                      onClick={() => !isAnswered && setSelectedAnswer(choice)}
                    />
                  );
                })}
              </div>
              {!isAnswered && (
                <Button
                  onClick={() => selectedAnswer && handleAnswer(selectedAnswer)}
                  variant="primary"
                  size="lg"
                  className="w-full"
                  disabled={!selectedAnswer}
                >
                  Xác nhận
                </Button>
              )}
            </div>
          ) : (
            <InputAnswer
              value={selectedAnswer}
              onChange={setSelectedAnswer}
              onConfirm={() => handleAnswer(selectedAnswer)}
              isAnswered={isAnswered}
              isCorrect={isInputCorrect}
              correctAnswer={currentQuestion.answer}
            />
          )}
        </QuestionCard>
      </AnimatePresence>
    </ScreenContainer>
  );
};

