/**
 * Google Sheet Service
 * Service để load câu hỏi từ Google Spreadsheet
 * Hỗ trợ cả CSV export và JSON format
 */

import { sheetsConfig, buildSheetUrl, buildPublishedSheetUrl } from '../config/sheets.config.js';

const STANDARD_COLUMNS = new Set([
  'id',
  'question',
  'type',
  'choices',
  'answer',
  'hint',
  'points',
  'explanation',
  'explain',
  'image_url',
  'image',
  'imageurl',
  'level',
  'level_id',
  'subject',
  'subject_id',
  'quiz_type',
  'group',
  'tags',
  'difficulty',
  'estimated_time',
  'time',
  'creator',
  'creator_id',
  'creator_name',
  'source',
  'source_url',
  'description',
  'title',
]);

const normalizeKey = (key = '') => key.trim().toLowerCase();

const collectChoiceValuesFromRow = (row) => {
  const dynamicChoices = [];

  Object.keys(row).forEach((originalKey) => {
    const value = row[originalKey];
    if (!value || !value.trim()) return;

    const key = normalizeKey(originalKey);
    if (key.startsWith('choice') || key.startsWith('option')) {
      dynamicChoices.push(value.trim());
      return;
    }

    if (!STANDARD_COLUMNS.has(key)) {
      dynamicChoices.push(value.trim());
    }
  });

  return dynamicChoices;
};

/**
 * Parse CSV string thành array of objects
 * @param {string} csvText - CSV text content
 * @param {boolean} hasHeader - Có header row không
 * @returns {Array<Object>} Array of objects
 */
const parseCSV = (csvText, hasHeader = true) => {
  // Normalize line endings
  const normalizedText = csvText.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const lines = normalizedText.split('\n').filter(line => line.trim());
  
  if (lines.length === 0) {
    console.warn('CSV is empty');
    return [];
  }

  // Parse header
  const headers = hasHeader 
    ? parseCSVLine(lines[0]).map(h => h.trim().replace(/^"|"$/g, '').toLowerCase())
    : null;

  console.log('CSV Headers:', headers);

  // Parse data rows
  const data = [];
  const startIndex = hasHeader ? 1 : 0;

  for (let i = startIndex; i < lines.length; i++) {
    const values = parseCSVLine(lines[i]);
    if (values.length === 0 || values.every(v => !v || !v.trim())) {
      continue; // Skip empty rows
    }

    if (hasHeader && headers) {
      const obj = {};
      headers.forEach((header, index) => {
        obj[header] = (values[index] || '').trim();
      });
      data.push(obj);
    } else {
      data.push(values);
    }
  }

  return data;
};

/**
 * Parse một dòng CSV, xử lý quotes và commas trong giá trị
 */
const parseCSVLine = (line) => {
  const values = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    
    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        // Escaped quote
        current += '"';
        i++;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      // End of value
      values.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  
  // Add last value
  values.push(current.trim());
  
  return values;
};

/**
 * Convert Google Sheet row data thành question object
 * Expected columns: id, question, type, choices (comma-separated), answer, hint, points
 */
const convertRowToQuestion = (row, index) => {
  // Nếu row là object (từ CSV với header)
  if (typeof row === 'object' && !Array.isArray(row)) {
    // Handle case-insensitive header keys
    const getValue = (key) => {
      const lowerKey = normalizeKey(key);
      return row[lowerKey] || row[key] || '';
    };

    const id = getValue('id') || `q${index + 1}`;
    const question = getValue('question') || '';
    const type = (getValue('type') || 'choice').toLowerCase();
    const answer = getValue('answer') || '';
    const hint = getValue('hint') || '';
    const points = parseInt(getValue('points')) || 10;
    const explanation = getValue('explanation') || getValue('explain') || '';
    const imageUrl = getValue('image_url') || getValue('image') || getValue('imageurl') || '';

    // Parse choices - handle both quoted and unquoted formats
    let choices = collectChoiceValuesFromRow(row);

    if (choices.length === 0) {
      const choicesStr = getValue('choices') || '';
      if (choicesStr && choicesStr.trim()) {
        const cleaned = choicesStr.replace(/^"|"$/g, '');
        choices = cleaned.split(',').map(c => c.trim()).filter(c => c);
      }
    }

    // Validate required fields
    if (!question || !question.trim()) {
      console.warn(`Row ${index + 1}: Missing question`, row);
      return null;
    }

    if (type === 'choice' && choices.length === 0) {
      console.warn(`Row ${index + 1}: Choice question without choices`, row);
    }

    if (!answer || !answer.trim()) {
      console.warn(`Row ${index + 1}: Missing answer`, row);
    }

    return {
      id,
      question: question.trim(),
      type,
      choices: choices.length > 0 ? choices : undefined,
      answer: answer.trim(),
      hint: hint.trim(),
      points,
      explanation: explanation.trim() || undefined,
      imageUrl: imageUrl.trim() || undefined,
    };
  }
  
  // Nếu row là array (từ CSV không có header)
  // Format (mới): [id, question, type, answer, hint, points, explanation, image_url, choice1, choice2, ...]
  // Format (cũ): [id, question, type, choices, answer, hint, points]
  if (Array.isArray(row)) {
    const id = row[0] || `q${index + 1}`;
    const question = row[1] || '';
    const type = (row[2] || 'choice').toLowerCase();

    const looksLikeOldFormat = row[3] && row[3].includes(',');

    if (looksLikeOldFormat) {
      const legacyChoices = row[3]
        ? row[3].split(',').map(c => c.trim()).filter(c => c)
        : [];

      return {
        id,
        question,
        type,
        choices: legacyChoices.length > 0 ? legacyChoices : undefined,
        answer: row[4] || '',
        hint: row[5] || '',
        points: parseInt(row[6]) || 10,
        explanation: row[7] || undefined,
        imageUrl: row[8] || undefined,
      };
    }

    const answer = row[3] || '';
    const hint = row[4] || '';
    const points = parseInt(row[5]) || 10;
    const explanation = row[6] || '';
    const imageUrl = row[7] || '';
    const tailChoices = row.slice(8).map(choice => (choice || '').trim()).filter(Boolean);

    return {
      id,
      question,
      type,
      choices: tailChoices.length > 0 ? tailChoices : undefined,
      answer,
      hint,
      points,
      explanation: explanation.trim() || undefined,
      imageUrl: imageUrl.trim() || undefined,
    };
  }
  
  return null;
};

/**
 * Fetch data từ Google Sheet CSV URL
 * @param {string} url - Google Sheet CSV export URL
 * @returns {Promise<Array>} Array of questions
 */
export const fetchFromGoogleSheetCSV = async (url) => {
  try {
    if (!url) {
      throw new Error('Google Sheet URL is required');
    }

    const response = await fetch(url);
    
    if (!response.ok) {
      throw new Error(`Failed to fetch Google Sheet: ${response.statusText}`);
    }

    const csvText = await response.text();
    console.log('CSV Text (first 500 chars):', csvText.substring(0, 500));
    
    const rows = parseCSV(csvText, true); // Assume first row is header
    console.log('Parsed rows count:', rows.length);
    console.log('First few rows:', rows.slice(0, 3));
    
    // Convert rows to questions
    const questions = rows
      .map((row, index) => {
        try {
          return convertRowToQuestion(row, index);
        } catch (err) {
          console.error(`Error converting row ${index}:`, err, row);
          return null;
        }
      })
      .filter(q => q && q.question && q.question.trim()); // Filter out invalid questions

    console.log('Converted questions count:', questions.length);
    if (questions.length > 0) {
      console.log('Sample question:', questions[0]);
    }

    return questions;
  } catch (error) {
    console.error('Error fetching from Google Sheet CSV:', error);
    throw error;
  }
};

/**
 * Fetch data từ Google Sheet bằng Sheet ID và GID
 * @param {string} sheetId - Google Sheet ID
 * @param {string} gid - Sheet GID (tab ID)
 * @returns {Promise<Array>} Array of questions
 */
export const fetchFromGoogleSheetById = async (sheetId, gid = '0') => {
  const url = buildSheetUrl(sheetId, gid);
  if (!url) {
    throw new Error('Sheet ID is required');
  }
  return fetchFromGoogleSheetCSV(url);
};

/**
 * Fetch data từ published Google Sheet
 * @param {string} sheetId - Google Sheet ID
 * @param {string} sheetName - Sheet name (tab name)
 * @returns {Promise<Array>} Array of questions
 */
export const fetchFromPublishedSheet = async (sheetId, sheetName = 'Sheet1') => {
  const url = buildPublishedSheetUrl(sheetId, sheetName);
  if (!url) {
    throw new Error('Sheet ID is required');
  }
  return fetchFromGoogleSheetCSV(url);
};

/**
 * Load questions cho một subject
 * Ưu tiên Google Sheet, fallback về JSON local
 * @param {string} subjectId - Subject ID (math, vietnamese, english)
 * @returns {Promise<Array>} Array of questions
 */
export const loadQuestionsForSubject = async (subjectId) => {
  const config = sheetsConfig[subjectId];
  if (!config) {
    console.warn(`No config found for subject: ${subjectId}`);
    return [];
  }

  try {
    // Thử load từ Google Sheet
    let questions = [];

    // Ưu tiên 1: Dùng URL trực tiếp
    if (config.url) {
      console.log(`Loading ${subjectId} from Google Sheet URL...`);
      questions = await fetchFromGoogleSheetCSV(config.url);
    }
    // Ưu tiên 2: Dùng Sheet ID và GID
    else if (config.sheetId) {
      console.log(`Loading ${subjectId} from Google Sheet ID...`);
      questions = await fetchFromGoogleSheetById(config.sheetId, config.gid);
    }

    if (questions && questions.length > 0) {
      console.log(`✅ Loaded ${questions.length} questions from Google Sheet for ${subjectId}`);
      return questions;
    }
  } catch (error) {
    console.warn(`⚠️ Failed to load from Google Sheet for ${subjectId}, using fallback:`, error);
  }

  // Fallback: Load từ JSON local
  try {
    if (config.fallback) {
      console.log(`Loading ${subjectId} from local JSON fallback...`);
      const response = await fetch(config.fallback);
      if (response.ok) {
        const data = await response.json();
        console.log(`✅ Loaded ${data.length} questions from local JSON for ${subjectId}`);
        return Array.isArray(data) ? data : [];
      }
    }
  } catch (error) {
    console.error(`❌ Failed to load fallback JSON for ${subjectId}:`, error);
  }

  return [];
};

/**
 * Load tất cả questions cho tất cả subjects
 * @returns {Promise<Object>} Object với keys là subject IDs và values là arrays of questions
 */
export const loadAllQuestions = async () => {
  const [math, vietnamese, english] = await Promise.all([
    loadQuestionsForSubject('math'),
    loadQuestionsForSubject('vietnamese'),
    loadQuestionsForSubject('english'),
  ]);

  return {
    math,
    vietnamese,
    english,
  };
};
