/**
 * Get all levels
 */
export const getAllLevels = () => {
  return Object.values(LEVEL_METADATA).sort((a, b) => a.order - b.order);
};

/**
 * Get level by ID
 */
export const getLevelById = (levelId) => {
  return LEVEL_METADATA[levelId] || null;
};

