import React, { useEffect, useState } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useLevelStore } from '../store/levelStore';
import { usePlayerStore } from '../store/playerStore';
import { useQuizStore } from '../store/quizStore';
import { loadQuizList, loadQuizData, searchQuizzes } from '../services/levelService.js';
import { getLevelById } from '../models/level.js';
import { getQuizTypeMetadata } from '../models/level.js';
import { soundService } from '../services/soundService';
import { Card } from '../components/Card';
import { Button } from '../components/Button';
import { Input } from '../components/Input';
import { ScreenContainer, Header, BackButton, OptionButton } from '../components/screen';

/**
 * QuizListScreen Component
 * Màn hình hiển thị danh sách bài test với đầy đủ metadata
 * Hỗ trợ filter và search
 */
export const QuizListScreen = () => {
  const { goToNext } = useFlowStore();
  const { 
    currentLevel, 
    currentSubject, 
    currentQuizType,
    filterSubject,
    filterQuizType,
    quizList, 
    setQuizList, 
    loadingQuizList, 
    setLoadingQuizList,
    setFilterSubject,
    setFilterQuizType,
    clearFilters,
  } = useLevelStore();
  const { currentPlayer } = usePlayerStore();
  const { setCurrentLesson } = useQuizStore();
  const [error, setError] = useState(null);
  const [searchKeyword, setSearchKeyword] = useState('');
  const [sortBy, setSortBy] = useState('usage'); // 'usage', 'rating', 'newest'

  useEffect(() => {
    loadQuizzes();
  }, [currentLevel, currentSubject, currentQuizType, filterSubject, filterQuizType, sortBy]);

  const loadQuizzes = async () => {
    try {
      setLoadingQuizList(true);
      setError(null);
      
      const filters = {
        levelId: currentLevel?.id,
        subjectId: filterSubject || currentSubject?.id,
        quizType: filterQuizType || currentQuizType,
        creatorId: currentQuizType === 'personal' ? currentPlayer?.id : null,
        sortBy,
      };

      let quizzes;
      if (searchKeyword.trim()) {
        quizzes = await searchQuizzes(searchKeyword.trim(), filters);
      } else {
        quizzes = await loadQuizList(filters);
      }
      
      setQuizList(quizzes);
    } catch (err) {
      console.error('Error loading quizzes:', err);
      setError(err.message);
    } finally {
      setLoadingQuizList(false);
    }
  };

  const handleSelectQuiz = async (quiz) => {
    soundService.playClick();
    
    try {
      // Load full quiz data (bao gồm questions)
      const quizData = await loadQuizData(quiz.id);
      
      if (!quizData || !quizData.questions || quizData.questions.length === 0) {
        alert('Không thể tải bài test này!');
        return;
      }

      // Set current lesson
      setCurrentLesson({
        id: quiz.id,
        name: quiz.title || quiz.id,
        description: quiz.description || '',
        icon: '📝',
        questions: quizData.questions,
      });

      goToNext('questionCount');
    } catch (error) {
      console.error('Error loading quiz data:', error);
      alert('Có lỗi khi tải bài test. Vui lòng thử lại!');
    }
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return 'Không rõ';
    try {
      const date = new Date(timestamp);
      const now = new Date();
      const diffMs = now - date;
      const diffMins = Math.floor(diffMs / 60000);
      const diffHours = Math.floor(diffMs / 3600000);
      const diffDays = Math.floor(diffMs / 86400000);

      if (diffMins < 1) return 'Vừa xong';
      if (diffMins < 60) return `${diffMins} phút trước`;
      if (diffHours < 24) return `${diffHours} giờ trước`;
      if (diffDays < 7) return `${diffDays} ngày trước`;
      
      return date.toLocaleDateString('vi-VN', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
    } catch {
      return 'Không rõ';
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    loadQuizzes();
  };

  const levelInfo = currentLevel ? getLevelById(currentLevel.id) : null;
  const typeInfo = currentQuizType ? getQuizTypeMetadata(currentQuizType) : null;

  if (loadingQuizList) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4 animate-spin">⏳</div>
          <p className="text-xl text-gray-600">Đang tải danh sách bài test...</p>
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <Header
        title="Danh sách bài test"
        subtitle={
          levelInfo && currentSubject && typeInfo
            ? `${levelInfo.name} - ${currentSubject.name} - ${typeInfo.name}`
            : 'Chọn cấp độ, môn học và loại'
        }
        titleClassName="text-4xl"
      />

      {/* Filters và Search */}
      <div className="mb-6 space-y-4">
        {/* Search */}
        <form onSubmit={handleSearch} className="flex gap-2">
          <Input
            type="text"
            value={searchKeyword}
            onChange={(e) => setSearchKeyword(e.target.value)}
            placeholder="Tìm kiếm bài test..."
            className="flex-1"
          />
          <Button type="submit" variant="primary">
            🔍
          </Button>
        </form>

        {/* Filters */}
        <div className="flex flex-wrap gap-2 items-center">
          <span className="text-sm font-semibold text-gray-700">Sắp xếp:</span>
          <OptionButton
            label="Phổ biến"
            selected={sortBy === 'usage'}
            onClick={() => setSortBy('usage')}
            size="sm"
          />
          <OptionButton
            label="Đánh giá cao"
            selected={sortBy === 'rating'}
            onClick={() => setSortBy('rating')}
            size="sm"
          />
          <OptionButton
            label="Mới nhất"
            selected={sortBy === 'newest'}
            onClick={() => setSortBy('newest')}
            size="sm"
          />
        </div>

        {/* Active filters */}
        {(filterSubject || filterQuizType) && (
          <div className="flex flex-wrap gap-2 items-center">
            <span className="text-sm text-gray-600">Bộ lọc:</span>
            {filterSubject && (
              <span className="px-3 py-1 bg-primary-100 text-primary-700 rounded-full text-sm">
                Môn: {filterSubject}
                <button
                  onClick={() => setFilterSubject(null)}
                  className="ml-2 hover:text-primary-900"
                >
                  ×
                </button>
              </span>
            )}
            {filterQuizType && (
              <span className="px-3 py-1 bg-primary-100 text-primary-700 rounded-full text-sm">
                Loại: {getQuizTypeMetadata(filterQuizType)?.name}
                <button
                  onClick={() => setFilterQuizType(null)}
                  className="ml-2 hover:text-primary-900"
                >
                  ×
                </button>
              </span>
            )}
            <Button
              variant="ghost"
              size="sm"
              onClick={clearFilters}
            >
              Xóa bộ lọc
            </Button>
          </div>
        )}
      </div>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-xl text-red-800 text-sm">
          ⚠️ {error}
        </div>
      )}

      {quizList.length === 0 ? (
        <Card className="text-center py-12">
          <div className="text-6xl mb-4">📭</div>
          <p className="text-xl text-gray-600 mb-2">Chưa có bài test nào</p>
          <p className="text-sm text-gray-500">
            {currentQuizType === 'personal' 
              ? 'Bạn có thể tạo bài test mới từ Google Sheet'
              : 'Hãy quay lại sau'}
          </p>
        </Card>
      ) : (
        <div className="space-y-4">
          {quizList.map((quiz, index) => {
            const quizLevel = getLevelById(quiz.levelId);
            const quizType = getQuizTypeMetadata(quiz.quizType);
            
            return (
              <Card
                key={quiz.id}
                onClick={() => handleSelectQuiz(quiz)}
                className="cursor-pointer"
              >
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1">
                    {/* Header với metadata */}
                    <div className="flex flex-wrap items-center gap-2 mb-2">
                      {quizLevel && (
                        <span className="px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs font-semibold">
                          {quizLevel.icon} {quizLevel.name}
                        </span>
                      )}
                      {quizType && (
                        <span className={`px-2 py-1 bg-gradient-to-r ${quizType.color} text-white rounded text-xs font-semibold`}>
                          {quizType.icon} {quizType.name}
                        </span>
                      )}
                      {quiz.difficulty && (
                        <span className="px-2 py-1 bg-gray-100 text-gray-700 rounded text-xs">
                          {quiz.difficulty === 'easy' ? 'Dễ' : quiz.difficulty === 'medium' ? 'Trung bình' : 'Khó'}
                        </span>
                      )}
                    </div>

                    <h3 className="text-xl font-bold text-gray-800 mb-2">
                      {quiz.title || quiz.id}
                    </h3>
                    
                    {quiz.description && (
                      <p className="text-gray-600 mb-3">{quiz.description}</p>
                    )}
                    
                    {/* Metadata */}
                    <div className="flex flex-wrap gap-4 text-sm text-gray-500 mb-3">
                      <span>📊 {quiz.questionCount || 0} câu hỏi</span>
                      {quiz.usageCount > 0 && (
                        <span>👥 {quiz.usageCount} người đã làm</span>
                      )}
                      {quiz.rating > 0 && (
                        <span>⭐ {quiz.rating.toFixed(1)} ({quiz.ratingCount || 0} đánh giá)</span>
                      )}
                      {quiz.creatorName && (
                        <span>✍️ {quiz.creatorName}</span>
                      )}
                      <span>📅 {formatDate(quiz.createdAt)}</span>
                      {quiz.estimatedTime > 0 && (
                        <span>⏱️ ~{quiz.estimatedTime} phút</span>
                      )}
                    </div>

                    {/* Tags */}
                    {quiz.tags && Array.isArray(quiz.tags) && quiz.tags.length > 0 && (
                      <div className="flex flex-wrap gap-2 mt-3">
                        {quiz.tags.map((tag, i) => (
                          <span
                            key={i}
                            className="px-2 py-1 bg-primary-100 text-primary-700 rounded-full text-xs"
                          >
                            {tag}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="ml-4 flex-shrink-0">
                    <Button variant="primary" size="md">
                      Làm bài →
                    </Button>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>
      )}

      <BackButton onClick={() => goToNext('quizTypeSelect')} />
    </ScreenContainer>
  );
};
