/**
 * Sync Service
 * Đồng bộ dữ liệu giữa IndexedDB (local) và Cloudflare D1 (cloud)
 */

import { cloudQuizzes, cloudResults, isCloudAvailable, testConnection } from './cloudService.js';
import { cacheQuiz, getCachedQuiz } from './storageService.js';

const parseJsonArray = (value) => {
  if (!value) return undefined;
  if (Array.isArray(value)) return value;
  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed) ? parsed : undefined;
  } catch (error) {
    return undefined;
  }
};

const transformQuizMetadata = (quiz = {}) => ({
  id: quiz.id,
  title: quiz.title || '',
  description: quiz.description || '',
  levelId: quiz.level_id || quiz.levelId || quiz.level || '',
  subjectId: quiz.subject_id || quiz.subjectId || quiz.subject || '',
  quizType: quiz.quiz_type || quiz.quizType || quiz.group || '',
  source: quiz.source_type || quiz.source || 'database',
  sourceUrl: quiz.source_url || quiz.sourceUrl || '',
  questionCount: quiz.question_count || quiz.questionCount || 0,
  creatorId: quiz.creator_id || quiz.creatorId || null,
  creatorName: quiz.creator_name || quiz.creatorName || '',
  createdAt: quiz.created_at || quiz.createdAt || Date.now(),
  updatedAt: quiz.updated_at || quiz.updatedAt || Date.now(),
  usageCount: quiz.usage_count || quiz.usageCount || 0,
  rating: quiz.rating || 0,
  ratingCount: quiz.rating_count || quiz.ratingCount || 0,
  difficulty: quiz.difficulty || 'medium',
  estimatedTime: quiz.estimated_time || quiz.estimatedTime || 0,
  isPublic: Boolean(quiz.is_public || quiz.isPublic),
  isVerified: Boolean(quiz.is_verified || quiz.isVerified),
  tags: typeof quiz.tags === 'string'
    ? JSON.parse(quiz.tags || '[]')
    : quiz.tags || [],
});

const transformQuizQuestions = (questions = [], quizId) => {
  return questions.map((question, index) => ({
    id: question.id || `${quizId}_q${index + 1}`,
    question: question.question_text || question.question || '',
    type: (question.question_type || question.type || 'choice').toLowerCase(),
    choices: parseJsonArray(question.choices),
    answer: question.answer || '',
    hint: question.hint || '',
    points: question.points || 10,
    explanation: question.explanation || question.explain || '',
    imageUrl: question.image_url || question.imageUrl || '',
    order: question.question_order || question.order || index + 1,
  }));
};

const hasMetadataChanged = (cached = {}, metadata = {}) => {
  if (!cached || !metadata) return true;
  const fields = ['levelId', 'subjectId', 'quizType', 'questionCount', 'title', 'description'];
  return fields.some((field) => {
    const cachedValue = cached[field];
    const metaValue = metadata[field];
    return cachedValue !== metaValue;
  });
};

/**
 * Sync official quizzes từ cloud về local
 * @param {Object} filters - Filter options
 * @returns {Promise<number>} Số lượng quizzes đã sync
 */
export const syncOfficialQuizzes = async (filters = {}) => {
  if (!isCloudAvailable()) {
    console.warn('Cloud service không khả dụng, bỏ qua sync');
    return 0;
  }

  try {
    // Load quizzes từ cloud
    const quizzesResponse = await cloudQuizzes.getQuizzes({
      ...filters,
      quizType: 'official',
    });
    const quizzes = Array.isArray(quizzesResponse)
      ? quizzesResponse
      : quizzesResponse?.results || [];

    let syncedCount = 0;

    // Load full data và cache vào local
    for (const quizMetadata of quizzes) {
      try {
        const normalizedMetadata = transformQuizMetadata(quizMetadata);

        // Check if already cached và up-to-date
        const cached = await getCachedQuiz(normalizedMetadata.id);
        const metadataChanged = hasMetadataChanged(cached, normalizedMetadata);
        if (
          cached &&
          cached.cachedAt &&
          cached.cachedAt >= (normalizedMetadata.updatedAt || 0) &&
          !metadataChanged
        ) {
          continue; // Skip nếu đã cache và up-to-date và metadata không đổi
        }

        // Load full quiz data từ cloud
        const fullQuiz = await cloudQuizzes.getQuiz(normalizedMetadata.id);
        
        if (fullQuiz) {
          const normalizedQuestions = transformQuizQuestions(
            Array.isArray(fullQuiz.questions)
              ? fullQuiz.questions
              : fullQuiz.questions?.results || [],
            normalizedMetadata.id
          );

          const normalizedQuiz = {
            ...normalizedMetadata,
            ...transformQuizMetadata(fullQuiz),
            questions: normalizedQuestions,
            cachedAt: Date.now(),
          };

          // Đảm bảo các key quan trọng luôn tồn tại
          normalizedQuiz.id =
            normalizedQuiz.id ||
            normalizedMetadata.id ||
            fullQuiz.id ||
            quizMetadata.id;

          normalizedQuiz.levelId = normalizedQuiz.levelId || normalizedMetadata.levelId;
          normalizedQuiz.subjectId = normalizedQuiz.subjectId || normalizedMetadata.subjectId;
          normalizedQuiz.quizType = normalizedQuiz.quizType || normalizedMetadata.quizType || 'official';

          // Cache vào IndexedDB
          await cacheQuiz(normalizedQuiz);
          syncedCount++;
        }
      } catch (error) {
        console.error(`Error syncing quiz ${quizMetadata.id}:`, error);
      }
    }

    console.log(`✅ Synced ${syncedCount} official quizzes`);
    return syncedCount;
  } catch (error) {
    console.error('Error syncing official quizzes:', error);
    throw error;
  }
};

/**
 * Upload community quiz lên cloud
 * @param {Object} quizData - Quiz data
 * @returns {Promise<Object>} Uploaded quiz
 */
export const uploadCommunityQuiz = async (quizData) => {
  if (!isCloudAvailable()) {
    throw new Error('Cloud service không khả dụng');
  }

  try {
    // Prepare quiz data for cloud
    const cloudData = {
      id: quizData.id,
      title: quizData.title,
      description: quizData.description,
      level_id: quizData.levelId || quizData.level_id,
      subject_id: quizData.subjectId || quizData.subject_id,
      quiz_type: quizData.quizType || quizData.quiz_type || quizData.group,
      source_type: quizData.source || quizData.source_type || 'google_sheet',
      source_url: quizData.sourceUrl || quizData.source_url,
      question_count: quizData.questionCount || quizData.question_count || 0,
      creator_id: quizData.creatorId || quizData.creator_id,
      creator_name: quizData.creatorName || quizData.creator_name,
      is_public: quizData.isPublic || quizData.is_public || false,
      tags: quizData.tags || [],
      difficulty: quizData.difficulty,
      estimated_time: quizData.estimatedTime || quizData.estimated_time,
      questions: quizData.questions || [],
    };

    const result = await cloudQuizzes.createQuiz(cloudData);
    
    // Update local cache với cloud metadata
    if (quizData.questions) {
      await cacheQuiz({
        ...quizData,
        cachedAt: Date.now(),
      });
    }

    return result;
  } catch (error) {
    console.error('Error uploading community quiz:', error);
    throw error;
  }
};

/**
 * Submit quiz result lên cloud
 * @param {Object} resultData - Result data
 * @returns {Promise<void>}
 */
export const syncResult = async (resultData) => {
  if (!isCloudAvailable()) {
    console.warn('Cloud service không khả dụng, result sẽ được lưu local only');
    return;
  }

  try {
    await cloudResults.submitResult({
      player_id: resultData.playerId,
      quiz_id: resultData.quizId,
      score: resultData.score,
      total_questions: resultData.totalQuestions,
      correct_answers: resultData.correctAnswers,
      time_taken: resultData.timeTaken,
      answers: resultData.answers || [],
    });
    console.log('✅ Result synced to cloud');
  } catch (error) {
    console.error('Error syncing result:', error);
    // Không throw error, vì result đã được lưu local
  }
};

/**
 * Sync all data (quizzes + results)
 * @param {Object} options - Sync options
 * @returns {Promise<Object>} Sync summary
 */
export const syncAll = async (options = {}) => {
  const summary = {
    quizzes: 0,
    results: 0,
    errors: [],
  };

  try {
    // Test connection
    const connected = await testConnection();
    if (!connected) {
      throw new Error('Không thể kết nối đến cloud service');
    }

    // Sync official quizzes
    if (options.syncQuizzes !== false) {
      try {
        summary.quizzes = await syncOfficialQuizzes(options.filters);
      } catch (error) {
        summary.errors.push(`Quizzes sync: ${error.message}`);
      }
    }

    // TODO: Sync results queue
    // if (options.syncResults !== false) {
    //   summary.results = await syncResultsQueue();
    // }

    return summary;
  } catch (error) {
    console.error('Error in syncAll:', error);
    summary.errors.push(error.message);
    throw error;
  }
};

/**
 * Check sync status
 * @returns {Promise<Object>} Sync status
 */
export const getSyncStatus = async () => {
  const status = {
    cloudAvailable: isCloudAvailable(),
    connected: false,
    lastSync: null,
    pendingSync: 0,
  };

  if (status.cloudAvailable) {
    try {
      status.connected = await testConnection();
    } catch (error) {
      console.error('Error checking connection:', error);
    }
  }

  // TODO: Load last sync time từ IndexedDB
  // const lastSync = await getLastSyncTime();
  // status.lastSync = lastSync;

  return status;
};



