import React, { useState, useEffect } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useLevelStore } from '../store/levelStore';
import { loadLevels, loadSubjectsForLevel } from '../services/levelService.js';
import { getQuizTypeMetadata, QUIZ_TYPES } from '../models/level.js';
import { soundService } from '../services/soundService';
import { Card } from '../components/Card';
import { Button } from '../components/Button';
import { ScreenContainer, Header, BackButton, OptionButton } from '../components/screen';

/**
 * QuizFilterScreen Component
 * Màn hình filter bài test theo môn hoặc loại
 * Cho phép xem tất cả bài test với filter
 */
export const QuizFilterScreen = () => {
  const { goToNext } = useFlowStore();
  const { 
    setFilterSubject, 
    setFilterQuizType,
    filterSubject,
    filterQuizType,
    clearFilters,
  } = useLevelStore();
  const [levels, setLevels] = useState([]);
  const [selectedLevel, setSelectedLevel] = useState(null);
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadLevelsData();
  }, []);

  useEffect(() => {
    if (selectedLevel) {
      loadSubjectsData();
    }
  }, [selectedLevel]);

  const loadLevelsData = async () => {
    try {
      const loadedLevels = await loadLevels();
      setLevels(loadedLevels);
    } catch (error) {
      console.error('Error loading levels:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadSubjectsData = async () => {
    try {
      const loadedSubjects = await loadSubjectsForLevel(selectedLevel.id);
      setSubjects(loadedSubjects);
    } catch (error) {
      console.error('Error loading subjects:', error);
    }
  };

  const handleApplyFilter = () => {
    soundService.playClick();
    goToNext('quizList');
  };

  const quizTypes = Object.values(QUIZ_TYPES).map(typeId => ({
    ...getQuizTypeMetadata(typeId),
    id: typeId,
  }));

  if (loading) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4 animate-spin">⏳</div>
          <p className="text-xl text-gray-600">Đang tải...</p>
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <Header
        title="Lọc bài test"
        subtitle="Chọn môn học hoặc loại bài test"
        titleClassName="text-4xl"
      />

      <div className="space-y-6">
        {/* Filter by Subject */}
        <Card>
          <h3 className="text-lg font-semibold text-gray-800 mb-4">
            Lọc theo môn học
          </h3>
          
          {/* Level selector */}
          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Chọn cấp độ:
            </label>
            <div className="grid grid-cols-3 gap-2">
              {levels.slice(0, 6).map((level) => (
                <OptionButton
                  key={level.id}
                  label={level.name}
                  icon={level.icon}
                  selected={selectedLevel?.id === level.id}
                  onClick={() => setSelectedLevel(level)}
                  size="sm"
                />
              ))}
            </div>
          </div>

          {/* Subject selector */}
          {selectedLevel && subjects.length > 0 && (
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Chọn môn:
              </label>
              <div className="grid grid-cols-2 gap-2">
                <OptionButton
                  label="Tất cả môn"
                  selected={!filterSubject}
                  onClick={() => setFilterSubject(null)}
                  size="sm"
                />
                {subjects.map((subject) => (
                  <OptionButton
                    key={subject.id}
                    label={subject.name}
                    icon={subject.icon}
                    selected={filterSubject === subject.id}
                    onClick={() => setFilterSubject(subject.id)}
                    size="sm"
                  />
                ))}
              </div>
            </div>
          )}
        </Card>

        {/* Filter by Type */}
        <Card>
          <h3 className="text-lg font-semibold text-gray-800 mb-4">
            Lọc theo loại
          </h3>
          <div className="grid grid-cols-3 gap-2">
            <OptionButton
              label="Tất cả"
              selected={!filterQuizType}
              onClick={() => setFilterQuizType(null)}
              size="sm"
            />
            {quizTypes.map((type) => (
              <OptionButton
                key={type.id}
                label={type.name}
                icon={type.icon}
                selected={filterQuizType === type.id}
                onClick={() => setFilterQuizType(type.id)}
                size="sm"
              />
            ))}
          </div>
        </Card>

        {/* Actions */}
        <div className="flex gap-4">
          <Button
            onClick={handleApplyFilter}
            variant="primary"
            size="lg"
            className="flex-1"
          >
            Áp dụng bộ lọc
          </Button>
          <Button
            onClick={() => {
              clearFilters();
              setSelectedLevel(null);
              setSubjects([]);
            }}
            variant="outline"
            size="lg"
          >
            Xóa tất cả
          </Button>
        </div>
      </div>

      <BackButton onClick={() => goToNext('home')} />
    </ScreenContainer>
  );
};



