import React from 'react';
import { motion } from 'framer-motion';
import { Button } from '../Button';
import { cn } from '../../utils';

/**
 * InputAnswer Component
 * Input field for text-based questions
 */
export const InputAnswer = ({
  value,
  onChange,
  onConfirm,
  isAnswered = false,
  isCorrect = false,
  correctAnswer = '',
  disabled = false,
  className = '',
  ...props
}) => {
  return (
    <div className={cn('space-y-4', className)} {...props}>
      <div className="relative">
        <input
          type="text"
          value={value}
          onChange={(e) => !isAnswered && onChange(e.target.value)}
          onKeyPress={(e) => {
            if (e.key === 'Enter' && value && !isAnswered) {
              onConfirm();
            }
          }}
          className={cn(
            'w-full px-4 py-3 border-2 rounded-lg text-lg focus:outline-none transition-all',
            isAnswered
              ? isCorrect
                ? 'border-green-500 bg-green-50'
                : 'border-red-500 bg-red-50'
              : 'border-gray-300 focus:border-primary-500'
          )}
          placeholder="Nhập câu trả lời..."
          disabled={isAnswered || disabled}
        />
        {isAnswered && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-2xl"
          >
            {isCorrect ? (
              <span className="text-green-600">✅</span>
            ) : (
              <span className="text-red-600">❌</span>
            )}
          </motion.div>
        )}
      </div>

      {isAnswered && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className={cn(
            'p-4 rounded-lg',
            isCorrect
              ? 'bg-green-50 border-2 border-green-200'
              : 'bg-red-50 border-2 border-red-200'
          )}
        >
          <div className="flex items-center gap-2 mb-2">
            <span className="text-lg font-semibold">
              {isCorrect ? 'Đúng rồi! 🎉' : 'Sai rồi! 😔'}
            </span>
          </div>
          {!isCorrect && correctAnswer && (
            <div className="text-sm text-gray-700">
              <span className="font-medium">Đáp án đúng:</span>{' '}
              <span className="font-semibold text-green-700">{correctAnswer}</span>
            </div>
          )}
        </motion.div>
      )}

      {!isAnswered && (
        <Button
          onClick={onConfirm}
          variant="primary"
          size="lg"
          className="w-full"
          disabled={!value || disabled}
        >
          Xác nhận
        </Button>
      )}
    </div>
  );
};

