/**
 * FlowManager Service
 * Quản lý flow điều hướng giữa các màn hình dựa trên flow.json
 */

let flowConfig = null;
let currentScreenId = null;

/**
 * Khởi tạo FlowManager với flow config
 * @param {Array} flow - Mảng các bước flow từ flow.json
 */
export const initFlow = async (flow) => {
  try {
    flowConfig = flow;
    // Bắt đầu từ màn hình đầu tiên
    if (flow && flow.length > 0) {
      currentScreenId = flow[0].id;
    }
    return { success: true, currentScreen: currentScreenId };
  } catch (error) {
    console.error('Error initializing flow:', error);
    return { success: false, error: error.message };
  }
};

/**
 * Lấy màn hình hiện tại
 * @returns {Object|null} Thông tin màn hình hiện tại
 */
export const getCurrentScreen = () => {
  if (!flowConfig || !currentScreenId) return null;
  return flowConfig.find(step => step.id === currentScreenId);
};

/**
 * Chuyển đến màn hình tiếp theo
 * @param {string} nextId - ID của màn hình tiếp theo (optional)
 * @returns {Object|null} Thông tin màn hình tiếp theo
 */
export const goToNext = (nextId = null) => {
  if (!flowConfig || !currentScreenId) return null;

  const currentScreen = getCurrentScreen();
  if (!currentScreen) return null;

  let targetId = nextId;

  // Nếu không có nextId, lấy từ currentScreen.next
  if (!targetId) {
    if (Array.isArray(currentScreen.next)) {
      // Nếu next là mảng, lấy phần tử đầu tiên (có thể mở rộng logic sau)
      targetId = currentScreen.next[0];
    } else {
      targetId = currentScreen.next;
    }
  }

  // Tìm màn hình tiếp theo
  const nextScreen = flowConfig.find(step => step.id === targetId);
  if (nextScreen) {
    currentScreenId = nextScreen.id;
    return nextScreen;
  }

  return null;
};

/**
 * Chuyển đến màn hình cụ thể
 * @param {string} screenId - ID của màn hình cần chuyển đến
 * @returns {Object|null} Thông tin màn hình
 */
export const goToScreen = (screenId) => {
  if (!flowConfig) return null;

  const screen = flowConfig.find(step => step.id === screenId);
  if (screen) {
    currentScreenId = screen.id;
    return screen;
  }

  return null;
};

/**
 * Lấy tất cả các màn hình có thể điều hướng từ màn hình hiện tại
 * @returns {Array} Danh sách các màn hình có thể điều hướng
 */
export const getAvailableNextScreens = () => {
  const currentScreen = getCurrentScreen();
  if (!currentScreen || !currentScreen.next) return [];

  if (Array.isArray(currentScreen.next)) {
    return currentScreen.next.map(id => 
      flowConfig.find(step => step.id === id)
    ).filter(Boolean);
  }

  const nextScreen = flowConfig.find(step => step.id === currentScreen.next);
  return nextScreen ? [nextScreen] : [];
};

/**
 * Reset flow về màn hình đầu tiên
 */
export const resetFlow = () => {
  if (flowConfig && flowConfig.length > 0) {
    currentScreenId = flowConfig[0].id;
  }
};

/**
 * Lấy toàn bộ flow config
 * @returns {Array} Flow config
 */
export const getFlowConfig = () => flowConfig;

