import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Button } from '../components/Button';
import { Card } from '../components/Card';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { soundService } from '../services/soundService';
import { ScreenContainer, Header, OptionButton } from '../components/screen';

/**
 * QuestionCountScreen Component
 * Màn hình chọn số lượng câu hỏi
 */
export const QuestionCountScreen = () => {
  const { goToNext } = useFlowStore();
  const { currentLesson, setQuestionCount } = useQuizStore();
  const [selectedCount, setSelectedCount] = useState(10);
  
  // Nếu chưa có lesson, quay lại chọn môn
  if (!currentLesson || !currentLesson.questions || currentLesson.questions.length === 0) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Chưa chọn môn học!</p>
          <Button onClick={() => goToNext('lessonSelect')} variant="primary">
            Quay lại chọn môn
          </Button>
        </div>
      </ScreenContainer>
    );
  }
  
  const maxQuestions = currentLesson.questions.length;
  const baseCounts = [5, 10, 20, 30, 50].filter(count => count <= maxQuestions);
  const questionCounts = maxQuestions > 50 && !baseCounts.includes(maxQuestions)
    ? [...baseCounts, maxQuestions]
    : baseCounts;

  const handleContinue = () => {
    soundService.playClick();
    setQuestionCount(selectedCount);
    goToNext('quizSettings');
  };

  return (
    <ScreenContainer maxWidth="2xl">
      <Header
        title="Chọn số lượng câu hỏi"
        titleClassName="text-4xl"
      />
      
      <motion.p
        className="text-center text-gray-600 mb-8"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
      >
        Môn: <span className="font-semibold">{currentLesson?.name}</span> ({maxQuestions} câu có sẵn)
      </motion.p>

      <Card>
        <div className="space-y-6">
          <div>
            <label className="block text-lg font-semibold text-gray-700 mb-4">
              Số lượng câu hỏi:
            </label>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
              {questionCounts.map((count) => (
                <OptionButton
                  key={count}
                  onClick={() => setSelectedCount(count)}
                  selected={selectedCount === count}
                >
                  {count} câu
                </OptionButton>
              ))}
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <Button
              onClick={handleContinue}
              variant="primary"
              size="lg"
              className="flex-1"
            >
              Tiếp tục →
            </Button>
            <Button
              onClick={() => goToNext('lessonSelect')}
              variant="outline"
              size="lg"
              className="flex-1"
            >
              ← Quay lại
            </Button>
          </div>
        </div>
      </Card>
    </ScreenContainer>
  );
};

