import React from 'react';
import { Card } from '../Card';
import { cn } from '../../utils';

/**
 * StatsCard Component
 * Reusable card for displaying statistics
 */
export const StatsCard = ({
  icon,
  value,
  label,
  valueColor = 'text-primary-600',
  className = '',
  ...props
}) => {
  return (
    <Card className={cn('text-center relative overflow-hidden', className)} {...props}>
      {/* Subtle gradient background */}
      <div className="absolute inset-0 bg-gradient-to-br from-primary-50/30 to-secondary-50/30 opacity-50" />
      <div className="relative z-10">
        {icon && (
          <div className="text-5xl mb-3 transform hover:scale-110 transition-transform duration-300">
            {icon}
          </div>
        )}
        <div className={cn('text-4xl font-bold mb-1 drop-shadow-sm', valueColor)}>
          {value}
        </div>
        <div className="text-sm text-gray-600 font-medium">{label}</div>
      </div>
    </Card>
  );
};

