import { create } from 'zustand';

/**
 * Quiz Store
 * Quản lý state của quiz hiện tại
 */
export const useQuizStore = create((set) => ({
  currentLesson: null,
  questionCount: 10,
  quizSettings: {
    scoringMode: 'basic',
    timeLimit: 30,
  },
  quizResult: null,

  setCurrentLesson: (lesson) => {
    set({ currentLesson: lesson });
  },

  setQuestionCount: (count) => {
    set({ questionCount: count });
  },

  setQuizSettings: (settings) => {
    set({ quizSettings: settings });
  },

  setQuizResult: (result) => {
    set({ quizResult: result });
  },

  clearQuiz: () => {
    set({
      currentLesson: null,
      questionCount: 10,
      quizSettings: {
        scoringMode: 'basic',
        timeLimit: 30,
      },
      quizResult: null,
    });
  },
}));

