import React from 'react';
import { motion } from 'framer-motion';
import { cn } from '../../utils';

/**
 * ChoiceButton Component
 * Button for multiple choice questions
 */
export const ChoiceButton = ({
  choice,
  isSelected = false,
  isCorrect = false,
  isAnswered = false,
  onClick,
  className = '',
  ...props
}) => {
  const showResult = isAnswered;
  
  let buttonClass = 'w-full p-4 rounded-xl border-2 text-left transition-all duration-300 shadow-sm';
  if (showResult) {
    if (isCorrect) {
      buttonClass += ' border-green-500 bg-gradient-to-r from-green-50 to-green-100 shadow-md shadow-green-200/50';
    } else if (isSelected && !isCorrect) {
      buttonClass += ' border-red-500 bg-gradient-to-r from-red-50 to-red-100 shadow-md shadow-red-200/50';
    } else {
      buttonClass += ' border-gray-300 bg-gray-50';
    }
  } else {
    buttonClass += isSelected
      ? ' border-primary-600 bg-gradient-to-r from-primary-50 to-primary-100 shadow-md shadow-primary-200/50'
      : ' border-gray-300 bg-white hover:border-primary-400 hover:bg-primary-50/50 hover:shadow-md';
  }

  return (
    <motion.button
      onClick={onClick}
      className={cn(buttonClass, className)}
      disabled={isAnswered}
      whileHover={!isAnswered ? { scale: 1.02 } : {}}
      whileTap={!isAnswered ? { scale: 0.98 } : {}}
      animate={
        showResult && isCorrect
          ? { scale: [1, 1.1, 1], rotate: [0, 5, -5, 0] }
          : showResult && isSelected && !isCorrect
          ? { x: [0, -10, 10, -10, 10, 0] }
          : {}
      }
      {...props}
    >
      <div className="flex items-center justify-between">
        <span className="text-lg font-medium text-gray-800">
          {choice}
        </span>
        {showResult && isCorrect && (
          <span className="text-2xl">✅</span>
        )}
        {showResult && isSelected && !isCorrect && (
          <span className="text-2xl">❌</span>
        )}
      </div>
    </motion.button>
  );
};

