import React, { useState, useEffect } from 'react';
import { useFlowStore } from '../store/flowStore';
import { usePlayerStore } from '../store/playerStore';
import { useLevelStore } from '../store/levelStore';
import { importQuizFromGoogleSheet } from '../services/quizManagementService.js';
import { loadLevels, loadSubjectsForLevel } from '../services/levelService.js';
import { QUIZ_TYPES } from '../models/level.js';
import { soundService } from '../services/soundService';
import { canCreateQuiz, getCurrentUser } from '../services/userService.js';
import { Card } from '../components/Card';
import { Button } from '../components/Button';
import { Input } from '../components/Input';
import { ScreenContainer, Header, BackButton, OptionButton } from '../components/screen';

/**
 * ImportQuizScreen Component
 * Màn hình import bài test từ Google Sheet
 */
export const ImportQuizScreen = () => {
  const { goToNext } = useFlowStore();
  const { currentPlayer } = usePlayerStore();
  
  const [sheetUrl, setSheetUrl] = useState('');
  const [selectedLevel, setSelectedLevel] = useState(null);
  const [selectedSubject, setSelectedSubject] = useState(null);
  const [selectedQuizType, setSelectedQuizType] = useState(QUIZ_TYPES.PERSONAL);
  const [isPublic, setIsPublic] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [levels, setLevels] = useState([]);
  const [subjects, setSubjects] = useState([]);

  const user = getCurrentUser(currentPlayer);
  const canCreate = canCreateQuiz(user);

  useEffect(() => {
    loadLevelsData();
  }, []);

  useEffect(() => {
    if (selectedLevel) {
      loadSubjectsData();
    }
  }, [selectedLevel]);

  const loadLevelsData = async () => {
    try {
      const loadedLevels = await loadLevels();
      setLevels(loadedLevels);
      // Default to grade3
      const defaultLevel = loadedLevels.find(l => l.id === 'grade3') || loadedLevels[0];
      if (defaultLevel) {
        setSelectedLevel(defaultLevel);
      }
    } catch (error) {
      console.error('Error loading levels:', error);
    }
  };

  const loadSubjectsData = async () => {
    try {
      const loadedSubjects = await loadSubjectsForLevel(selectedLevel.id);
      setSubjects(loadedSubjects);
      if (loadedSubjects.length > 0) {
        setSelectedSubject(loadedSubjects[0]);
      }
    } catch (error) {
      console.error('Error loading subjects:', error);
    }
  };

  const quizTypes = [
    {
      id: QUIZ_TYPES.PERSONAL,
      name: 'Cá nhân',
      description: 'Chỉ bạn mới thấy',
      icon: '👤',
    },
    {
      id: QUIZ_TYPES.COMMUNITY,
      name: 'Cộng đồng',
      description: 'Chia sẻ với mọi người',
      icon: '👥',
    },
  ];

  const handleImport = async () => {
    if (!sheetUrl.trim()) {
      setError('Vui lòng nhập URL Google Sheet');
      return;
    }

    if (!selectedLevel || !selectedSubject) {
      setError('Vui lòng chọn cấp độ và môn học');
      return;
    }

    if (!canCreate) {
      setError('Bạn không có quyền tạo bài test');
      return;
    }

    try {
      setLoading(true);
      setError(null);
      setSuccess(false);

      const quizData = await importQuizFromGoogleSheet(
        sheetUrl.trim(),
        selectedQuizType,
        selectedLevel.id,
        selectedSubject.id,
        currentPlayer.id,
        isPublic
      );

      setSuccess(true);
      soundService.playSuccess();

      // Reset form sau 2 giây
      setTimeout(() => {
        setSheetUrl('');
        setSelectedLevel(levels.find(l => l.id === 'grade3') || levels[0]);
        setSelectedSubject(null);
        setIsPublic(false);
        setSuccess(false);
      }, 2000);
    } catch (err) {
      console.error('Error importing quiz:', err);
      setError(err.message || 'Có lỗi khi import bài test. Vui lòng kiểm tra lại URL.');
      soundService.playError();
    } finally {
      setLoading(false);
    }
  };

  if (!canCreate) {
    return (
      <ScreenContainer>
        <Header
          title="Tạo bài test"
          subtitle="Bạn cần quyền để tạo bài test"
        />
        <Card className="text-center py-8">
          <div className="text-6xl mb-4">🔒</div>
          <p className="text-xl text-gray-600 mb-4">
            Bạn không có quyền tạo bài test
          </p>
          <p className="text-sm text-gray-500 mb-6">
            Chỉ phụ huynh và giáo viên mới có thể tạo bài test
          </p>
          <BackButton onClick={() => goToNext('home')} />
        </Card>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <Header
        title="Tạo bài test từ Google Sheet"
        subtitle="Import câu hỏi từ Google Spreadsheet"
      />

      {error && (
        <Card className="mb-4 p-4 bg-red-50 border border-red-200">
          <p className="text-red-800 text-sm">⚠️ {error}</p>
        </Card>
      )}

      {success && (
        <Card className="mb-4 p-4 bg-green-50 border border-green-200">
          <p className="text-green-800 text-sm">✅ Import thành công! Bài test đã được lưu.</p>
        </Card>
      )}

      <div className="space-y-6">
        {/* Google Sheet URL */}
        <Card>
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            URL Google Sheet *
          </label>
          <Input
            type="url"
            value={sheetUrl}
            onChange={(e) => setSheetUrl(e.target.value)}
            placeholder="https://docs.google.com/spreadsheets/d/..."
            className="w-full"
            disabled={loading}
          />
          <p className="text-xs text-gray-500 mt-2">
            📝 Lưu ý: Sheet phải được publish to web (CSV format)
          </p>
        </Card>

        {/* Chọn cấp độ */}
        <Card>
          <label className="block text-sm font-semibold text-gray-700 mb-3">
            Chọn cấp độ *
          </label>
          <div className="grid grid-cols-3 gap-2 max-h-48 overflow-y-auto">
            {levels.map((level) => (
              <OptionButton
                key={level.id}
                label={level.name}
                description={level.description}
                icon={level.icon}
                selected={selectedLevel?.id === level.id}
                onClick={() => setSelectedLevel(level)}
                disabled={loading}
                size="sm"
              />
            ))}
          </div>
        </Card>

        {/* Chọn môn học */}
        {selectedLevel && (
          <Card>
            <label className="block text-sm font-semibold text-gray-700 mb-3">
              Chọn môn học *
            </label>
            <div className="grid grid-cols-2 gap-3">
              {subjects.map((subject) => (
                <OptionButton
                  key={subject.id}
                  label={subject.name}
                  description={subject.description}
                  icon={subject.icon}
                  selected={selectedSubject?.id === subject.id}
                  onClick={() => setSelectedSubject(subject)}
                  disabled={loading}
                />
              ))}
            </div>
          </Card>
        )}

        {/* Chọn loại */}
        <Card>
          <label className="block text-sm font-semibold text-gray-700 mb-3">
            Chọn loại bài test
          </label>
          <div className="grid grid-cols-2 gap-3">
            {quizTypes.map((type) => (
              <OptionButton
                key={type.id}
                label={type.name}
                description={type.description}
                icon={type.icon}
                selected={selectedQuizType === type.id}
                onClick={() => setSelectedQuizType(type.id)}
                disabled={loading}
              />
            ))}
          </div>
        </Card>

        {/* Public option (chỉ cho community) */}
        {selectedQuizType === QUIZ_TYPES.COMMUNITY && (
          <Card>
            <label className="flex items-center space-x-3 cursor-pointer">
              <input
                type="checkbox"
                checked={isPublic}
                onChange={(e) => setIsPublic(e.target.checked)}
                disabled={loading}
                className="w-5 h-5 text-primary-600 rounded focus:ring-primary-500"
              />
              <div>
                <span className="text-sm font-semibold text-gray-700">
                  Chia sẻ công khai
                </span>
                <p className="text-xs text-gray-500">
                  Bài test sẽ hiển thị trong nhóm Cộng đồng cho mọi người
                </p>
              </div>
            </label>
          </Card>
        )}

        {/* Action buttons */}
        <div className="flex gap-4">
          <Button
            onClick={handleImport}
            variant="primary"
            size="lg"
            disabled={loading || !sheetUrl.trim() || !selectedLevel || !selectedSubject}
            className="flex-1"
          >
            {loading ? '⏳ Đang import...' : '📥 Import bài test'}
          </Button>
          <Button
            onClick={() => goToNext('home')}
            variant="outline"
            size="lg"
            disabled={loading}
          >
            Hủy
          </Button>
        </div>
      </div>

      {/* Hướng dẫn */}
      <Card className="mt-6 bg-blue-50 border-blue-200">
        <h3 className="text-sm font-semibold text-blue-900 mb-2">
          📖 Hướng dẫn:
        </h3>
        <ol className="text-xs text-blue-800 space-y-1 list-decimal list-inside">
          <li>Tạo Google Sheet với format: id, question, type, choices, answer, hint, points</li>
          <li>File → Share → Publish to web → Chọn CSV format</li>
          <li>Copy link và paste vào ô trên</li>
          <li>Chọn nhóm và môn học, sau đó click Import</li>
        </ol>
      </Card>

      <BackButton onClick={() => goToNext('home')} />
    </ScreenContainer>
  );
};

