import React, { useState, useEffect } from 'react';
import { Button } from '../components/Button';
import { Card } from '../components/Card';
import { useFlowStore } from '../store/flowStore';
import { useQuizStore } from '../store/quizStore';
import { soundService } from '../services/soundService';
import { ScreenContainer, Header, SettingCard, OptionButton } from '../components/screen';

/**
 * SettingsScreen Component
 * Màn hình cài đặt chung
 */
export const SettingsScreen = () => {
  const { goToNext } = useFlowStore();
  const { quizSettings, setQuizSettings } = useQuizStore();
  const [scoringMode, setScoringMode] = useState(quizSettings?.scoringMode || 'basic');
  const [timeLimit, setTimeLimit] = useState(quizSettings?.timeLimit || 30);

  useEffect(() => {
    // Load current settings
    if (quizSettings) {
      setScoringMode(quizSettings.scoringMode || 'basic');
      setTimeLimit(quizSettings.timeLimit || 30);
    }
  }, [quizSettings]);

  const handleSave = () => {
    soundService.playClick();
    setQuizSettings({
      scoringMode,
      timeLimit,
    });
    alert('Đã lưu cài đặt!');
    goToNext('home');
  };

  return (
    <ScreenContainer maxWidth="2xl">
      <Header
        title="⚙️ Cài đặt"
        titleClassName="text-4xl"
      />

      <Card>
        <div className="space-y-6">
          <div>
            <label className="block text-lg font-semibold text-gray-700 mb-3">
              Chế độ tính điểm:
            </label>
            <div className="space-y-2">
              <SettingCard
                title="Cơ bản"
                description="Mỗi câu đúng = 1 điểm, tổng quy về 100"
                selected={scoringMode === 'basic'}
                onClick={() => setScoringMode('basic')}
              />
              <SettingCard
                title="Theo thời gian"
                description="Trả lời nhanh sẽ được thêm điểm"
                selected={scoringMode === 'time'}
                onClick={() => setScoringMode('time')}
              />
            </div>
          </div>

          <div>
            <label className="block text-lg font-semibold text-gray-700 mb-3">
              Thời gian mỗi câu (giây):
            </label>
            <div className="flex gap-2">
              {[15, 30, 60, 0].map((time) => (
                <OptionButton
                  key={time}
                  onClick={() => setTimeLimit(time)}
                  selected={timeLimit === time}
                  className="flex-1 p-3"
                >
                  {time === 0 ? 'Không giới hạn' : `${time}s`}
                </OptionButton>
              ))}
            </div>
          </div>

          <div className="flex gap-4 pt-4">
            <Button
              onClick={handleSave}
              variant="primary"
              size="lg"
              className="flex-1"
            >
              💾 Lưu cài đặt
            </Button>
            <Button
              onClick={() => goToNext('home')}
              variant="outline"
              size="lg"
              className="flex-1"
            >
              ← Quay lại
            </Button>
          </div>
        </div>
      </Card>
    </ScreenContainer>
  );
};

