/**
 * Test Cloud Connection Utility
 * Chạy trong browser console để test kết nối cloud
 */

import { testConnection, cloudQuizzes } from '../services/cloudService.js';
import { syncOfficialQuizzes, getSyncStatus } from '../services/syncService.js';

/**
 * Test connection
 */
export const test = async () => {
  console.log('🔍 Testing cloud connection...');
  
  try {
    const status = await getSyncStatus();
    console.log('📊 Sync Status:', status);
    
    if (!status.cloudAvailable) {
      console.warn('⚠️ Cloud service chưa được cấu hình');
      console.log('💡 Thêm VITE_CLOUDFLARE_API_URL vào .env');
      return;
    }
    
    if (!status.connected) {
      console.error('❌ Không thể kết nối đến cloud service');
      return;
    }
    
    console.log('✅ Connection successful!');
    
    // Test get quizzes
    console.log('📥 Testing get quizzes...');
    const quizzes = await cloudQuizzes.getQuizzes({ limit: 5 });
    console.log(`✅ Loaded ${quizzes.length} quizzes:`, quizzes);
    
    return { success: true, quizzes };
  } catch (error) {
    console.error('❌ Test failed:', error);
    return { success: false, error: error.message };
  }
};

/**
 * Test sync
 */
export const testSync = async () => {
  console.log('🔄 Testing sync...');
  
  try {
    const count = await syncOfficialQuizzes();
    console.log(`✅ Synced ${count} quizzes`);
    return { success: true, count };
  } catch (error) {
    console.error('❌ Sync failed:', error);
    return { success: false, error: error.message };
  }
};

// Export for browser console
if (typeof window !== 'undefined') {
  window.testCloud = test;
  window.testSync = testSync;
  console.log('💡 Chạy testCloud() hoặc testSync() trong console để test');
}



