import React, { useEffect, useState } from 'react';
import { useFlowStore } from '../store/flowStore';
import { useLevelStore } from '../store/levelStore';
import { usePlayerStore } from '../store/playerStore';
import { QUIZ_TYPES, QUIZ_TYPE_METADATA } from '../models/level.js';
import { getQuizTypeStatsMap } from '../services/quizStatsService.js';
import { soundService } from '../services/soundService';
import { formatCompactNumber, formatRatingValue } from '../utils/numberFormat.js';
import { ScreenContainer, Header, SubjectCard, BackButton } from '../components/screen';

/**
 * QuizTypeSelectScreen Component
 * Màn hình chọn loại bài test (Hệ thống, Cộng đồng, Cá nhân)
 */
export const QuizTypeSelectScreen = () => {
  const { goToNext } = useFlowStore();
  const { currentLevel, currentSubject, setCurrentQuizType } = useLevelStore();
  const { currentPlayer } = usePlayerStore();
  const [typeStats, setTypeStats] = useState({});
  const [statsLoading, setStatsLoading] = useState(true);

  const quizTypes = Object.values(QUIZ_TYPES).map(typeId => ({
    ...QUIZ_TYPE_METADATA[typeId],
    id: typeId,
  }));

  useEffect(() => {
    if (currentLevel && currentSubject) {
      loadTypeStats(currentLevel.id, currentSubject.id);
    }
  }, [currentLevel, currentSubject]);

  const loadTypeStats = async (levelId, subjectId) => {
    try {
      setStatsLoading(true);
      const stats = await getQuizTypeStatsMap(levelId, subjectId);
      setTypeStats(stats || {});
    } catch (error) {
      console.error('Error loading quiz type stats:', error);
    } finally {
      setStatsLoading(false);
    }
  };

  const handleSelectType = (quizType) => {
    soundService.playClick();
    setCurrentQuizType(quizType.id);
    goToNext('quizList');
  };

  if (!currentLevel || !currentSubject) {
    return (
      <ScreenContainer className="flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Chưa chọn cấp độ hoặc môn học!</p>
          <BackButton onClick={() => goToNext('subjectSelect')} />
        </div>
      </ScreenContainer>
    );
  }

  return (
    <ScreenContainer>
      <BackButton
        inline
        variant="ghost"
        label="← Quay lại"
        onClick={() => goToNext('subjectSelect')}
        className="mb-2"
      />
      <Header
        title="Chọn loại bài test"
        subtitle={`${currentLevel.name} - ${currentSubject.name}`}
        titleClassName="text-4xl"
      />

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {quizTypes.map((type, index) => {
          const stats = typeStats[type.id] || {};
          const statItems = [
            { label: 'Bài test', value: statsLoading ? '…' : formatCompactNumber(stats.quizCount) },
            { label: 'Lượt làm', value: statsLoading ? '…' : formatCompactNumber(stats.totalUsage) },
            { label: 'Người học', value: statsLoading ? '…' : formatCompactNumber(stats.playerCount) },
            { label: 'Đánh giá', value: statsLoading ? '…' : formatRatingValue(stats.averageRating) },
          ];

          return (
            <SubjectCard
              key={type.id}
              icon={type.icon}
              title={type.name}
              description={type.description}
              onClick={() => handleSelectType(type)}
              delay={index * 0.1}
              className={`bg-gradient-to-br ${type.color} text-white border-0`}
              stats={statItems}
              statsVariant="dark"
              titleClassName="text-2xl font-bold text-white mb-2"
              descriptionClassName="text-white/80"
              iconClassName="text-6xl mb-4 transform group-hover:scale-110 transition-transform duration-300 drop-shadow-lg"
            />
          );
        })}
      </div>

    </ScreenContainer>
  );
};



