/**
 * Cloud Service
 * Service để giao tiếp với Cloudflare D1 qua Worker API
 */

const API_BASE_URL = import.meta.env.VITE_CLOUDFLARE_API_URL || '';

/**
 * Check if cloud service is available
 */
export const isCloudAvailable = () => {
  return !!API_BASE_URL && API_BASE_URL.trim() !== '';
};

/**
 * Make API request với error handling
 */
const apiRequest = async (endpoint, options = {}) => {
  if (!isCloudAvailable()) {
    throw new Error('Cloudflare API URL chưa được cấu hình. Vui lòng thêm VITE_CLOUDFLARE_API_URL vào .env');
  }

  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({ error: response.statusText }));
      throw new Error(error.error || `HTTP ${response.status}: ${response.statusText}`);
    }

    return await response.json();
  } catch (error) {
    console.error(`API Error (${endpoint}):`, error);
    throw error;
  }
};

/**
 * Quizzes API
 */
export const cloudQuizzes = {
  /**
   * Get quizzes với filters
   * @param {Object} filters - { levelId, subjectId, quizType, creatorId, sortBy }
   * @returns {Promise<Array>} Array of quizzes
   */
  async getQuizzes(filters = {}) {
    const params = new URLSearchParams();
    
    if (filters.levelId) params.append('levelId', filters.levelId);
    if (filters.subjectId) params.append('subjectId', filters.subjectId);
    if (filters.quizType) params.append('quizType', filters.quizType);
    if (filters.creatorId) params.append('creatorId', filters.creatorId);
    if (filters.sortBy) params.append('sortBy', filters.sortBy);
    
    // Backward compatibility
    if (filters.group) params.append('group', filters.group);
    if (filters.subject) params.append('subject', filters.subject);

    return apiRequest(`/api/quizzes?${params.toString()}`);
  },

  /**
   * Get quiz by ID (với questions)
   * @param {string} quizId - Quiz ID
   * @returns {Promise<Object>} Quiz data với questions
   */
  async getQuiz(quizId) {
    return apiRequest(`/api/quizzes/${quizId}`);
  },

  /**
   * Create quiz
   * @param {Object} quizData - Quiz data
   * @returns {Promise<Object>} Created quiz
   */
  async createQuiz(quizData) {
    return apiRequest('/api/quizzes', {
      method: 'POST',
      body: JSON.stringify(quizData),
    });
  },
};

/**
 * Results API
 */
export const cloudResults = {
  /**
   * Submit quiz result
   * @param {Object} resultData - Result data
   * @returns {Promise<Object>} Success response
   */
  async submitResult(resultData) {
    return apiRequest('/api/results', {
      method: 'POST',
      body: JSON.stringify(resultData),
    });
  },
};

/**
 * Users API
 */
export const cloudUsers = {
  /**
   * Get users
   * @returns {Promise<Array>} Array of users
   */
  async getUsers() {
    return apiRequest('/api/users');
  },
};

/**
 * Test connection
 */
export const testConnection = async () => {
  try {
    const response = await fetch(`${API_BASE_URL}/api/quizzes?limit=1`);
    return response.ok;
  } catch (error) {
    console.error('Connection test failed:', error);
    return false;
  }
};



