import React from 'react';
import { motion } from 'framer-motion';
import { cn } from '../../utils';

/**
 * QuestionCard Component
 * Card for displaying question content
 */
export const QuestionCard = ({
  question,
  questionNumber,
  imageUrl,
  hint,
  explanation,
  showExplanation = false,
  children,
  className = '',
  ...props
}) => {
  return (
    <motion.div
      initial={{ opacity: 0, x: 100 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -100 }}
      transition={{ duration: 0.3 }}
      {...props}
    >
      <div className={cn(
        'bg-white rounded-2xl shadow-xl p-6 mb-6 border border-gray-100',
        'backdrop-blur-sm bg-white/95',
        className
      )}>
        <div className="flex flex-col gap-2 mb-4">
          {typeof questionNumber === 'number' && (
            <div className="text-sm font-semibold text-primary-600 uppercase tracking-wide">
              Câu {questionNumber}
            </div>
          )}
          <h2 className="text-2xl font-bold bg-gradient-to-r from-gray-800 to-gray-700 bg-clip-text text-transparent">
            {question}
          </h2>
        </div>

        {imageUrl && (
          <div className="mb-4">
            <img
              src={imageUrl}
              alt={`Question illustration ${questionNumber || ''}`}
              className="w-full max-h-64 object-cover rounded-2xl border border-gray-100"
              loading="lazy"
            />
          </div>
        )}

        {hint && (
          <div className="bg-primary-50/50 border-l-4 border-primary-500 rounded-r-lg p-3 mb-4">
            <p className="text-sm text-gray-700 font-medium">
              💡 <span className="font-semibold">Gợi ý:</span> {hint}
            </p>
          </div>
        )}

        {children}

        {showExplanation && explanation && (
          <div className="mt-6 bg-amber-50 border border-amber-200 rounded-2xl p-4">
            <p className="text-sm font-semibold text-amber-800 mb-2">Giải thích</p>
            <p className="text-sm text-amber-900 leading-relaxed">
              {explanation}
            </p>
          </div>
        )}
      </div>
    </motion.div>
  );
};

