import React from 'react';
import { motion } from 'framer-motion';
import { cn } from '../../utils';

/**
 * OptionButton Component
 * Reusable button for selecting options (e.g., question count, time limit)
 */
export const OptionButton = ({
  children,
  onClick,
  selected = false,
  className = '',
  ...props
}) => {
  return (
    <motion.button
      onClick={onClick}
      className={cn(
        'p-4 rounded-xl border-2 transition-all duration-300 shadow-sm',
        selected
          ? 'border-primary-600 bg-gradient-to-br from-primary-50 to-primary-100 font-semibold text-primary-700 shadow-md shadow-primary-200/50'
          : 'border-gray-300 bg-white hover:border-primary-400 hover:bg-primary-50/50 hover:shadow-md',
        className
      )}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      {...props}
    >
      {children}
    </motion.button>
  );
};

